REPLACE INTO `ai_scenario_assessment_versions` (`id`, `ai_scenario_config_id`, `version_number`, `status`, `disaster_type`, `difficulty`, `estimated_time_minutes`, `scenario_title`, `title_en`, `title_fil`, `generated_scenario`, `description_en`, `description_fil`, `learning_objectives_en`, `learning_objectives_fil`, `generated_questions`, `generated_language`, `change_note`, `parent_version_id`, `created_by`, `approved_by`, `approved_at`, `published_at`, `published_by`, `last_edited_by`, `last_edited_at`, `created_at`, `updated_at`) VALUES
	(1, 1, 1, 'published', 'Fire', 'medium', 12, 'Fire Incident at Barangay Multi-Purpose Hall', 'Fire Incident at Barangay Multi-Purpose Hall', 'Insidente ng Sunog sa Barangay Multi-Purpose Hall', 'It\'s a busy Monday morning at the Barangay Maharlika Multi-Purpose Hall. The hall, frequently used for community meetings, LGU outreach programs, and as a temporary evacuation center, is currently hosting a livelihood training seminar for local women. Approximately 50 participants, along with five LGU staff members, are present. Suddenly, a strong burning smell fills the air, originating from the small pantry area adjacent to the main hall, where a refrigerator, microwave, and an electric kettle are located. Smoke begins to visibly emanate from the pantry door, and a low crackling sound can be heard. Some participants recall a recent issue with an overloaded extension cord in the pantry that was never fully addressed.\n\nPanic starts to spread among the participants, some of whom are blocking the main exit in their confusion. An LGU staff member quickly identifies the smoke source and realizes the situation is escalating. There are two fire extinguishers visible in the main hall: a red ABC dry chemical extinguisher mounted near the entrance, and a smaller, older CO2 extinguisher near the stage. The LGU staff are trained in basic fire safety, but the number of people and the growing smoke present a significant challenge for emergency response and evacuation.', 'It\'s a busy Monday morning at the Barangay Maharlika Multi-Purpose Hall. The hall, frequently used for community meetings, LGU outreach programs, and as a temporary evacuation center, is currently hosting a livelihood training seminar for local women. Approximately 50 participants, along with five LGU staff members, are present. Suddenly, a strong burning smell fills the air, originating from the small pantry area adjacent to the main hall, where a refrigerator, microwave, and an electric kettle are located. Smoke begins to visibly emanate from the pantry door, and a low crackling sound can be heard. Some participants recall a recent issue with an overloaded extension cord in the pantry that was never fully addressed.\n\nPanic starts to spread among the participants, some of whom are blocking the main exit in their confusion. An LGU staff member quickly identifies the smoke source and realizes the situation is escalating. There are two fire extinguishers visible in the main hall: a red ABC dry chemical extinguisher mounted near the entrance, and a smaller, older CO2 extinguisher near the stage. The LGU staff are trained in basic fire safety, but the number of people and the growing smoke present a significant challenge for emergency response and evacuation.', 'Abalang umaga ng Lunes sa Barangay Maharlika Multi-Purpose Hall. Ang bulwagan, na madalas gamitin para sa mga pagpupulong ng komunidad, mga programang outreach ng LGU, at bilang pansamantalang sentro ng paglikas, ay kasalukuyang nagho-host ng seminar sa pagsasanay sa pangkabuhayan para sa mga kababaihan sa lokalidad. Humigit-kumulang 50 kalahok, kasama ang limang kawani ng LGU, ang naroroon. Bigla, isang matinding amoy ng sunog ang kumalat sa hangin, na nagmula sa maliit na pantry na katabi ng pangunahing bulwagan, kung saan matatagpuan ang isang refrigerator, microwave, at electric kettle. Nagsisimulang makita ang usok na lumalabas mula sa pinto ng pantry, at isang mahina na ugong ng pagliyab ang naririnig. Naaalala ng ilang kalahok ang isang kamakailang isyu sa sobrang kargadong extension cord sa pantry na hindi lubos na natugunan.\n\nNagsimulang kumalat ang takot sa mga kalahok, kung saan ang ilan ay humaharang sa pangunahing labasan dahil sa pagkalito. Mabilis na natukoy ng isang kawani ng LGU ang pinagmulan ng usok at napagtanto na lumalala ang sitwasyon. Mayroong dalawang fire extinguisher na nakikita sa pangunahing bulwagan: isang pulang ABC dry chemical extinguisher na nakasabit malapit sa pasukan, at isang mas maliit, at mas lumang CO2 extinguisher malapit sa entablado. Ang mga kawani ng LGU ay sinanay sa pangunahing kaligtasan sa sunog, ngunit ang dami ng tao at ang lumalalang usok ay nagpapakita ng malaking hamon para sa tugon sa emerhensiya at paglikas.', 'To evaluate participants\' ability to identify common fire hazards and apply fire prevention practices in public facilities.\nTo assess understanding of immediate emergency response protocols during a fire incident, including alarm activation and calling for help.\nTo test participants\' decision-making regarding the safe use of fire extinguishers versus prioritizing evacuation in a developing fire scenario.\nTo reinforce the importance of proper evacuation procedures and crowd management during an emergency for diverse groups.\nTo measure knowledge of the types of fire extinguishers and their appropriate applications.', 'Upang suriin ang kakayahan ng mga kalahok na matukoy ang mga karaniwang panganib sa sunog at mailapat ang mga kasanayan sa pag-iwas sa sunog sa mga pampublikong pasilidad.\nUpang matasa ang pag-unawa sa mga agarang protocol ng pagtugon sa emerhensiya sa panahon ng insidente ng sunog, kabilang ang pag-aktiba ng alarma at pagtawag para sa tulong.\nUpang subukan ang paggawa ng desisyon ng mga kalahok tungkol sa ligtas na paggamit ng fire extinguisher kumpara sa pagbibigay-prayoridad sa paglikas sa isang lumalalang sitwasyon ng sunog.\nUpang bigyang-diin ang kahalagahan ng wastong pamamaraan ng paglikas at pamamahala ng maraming tao sa panahon ng isang emerhensiya para sa iba\'t ibang grupo.\nUpang sukatin ang kaalaman tungkol sa mga uri ng fire extinguisher at ang kanilang angkop na paggamit.', '[{"number":1,"competency":"safety_awareness","correct_answer":"B","question_en":"Based on the scenario, what is the most likely initial cause of the fire in the pantry?","question_fil":"Batay sa sitwasyon, ano ang pinakamalamang na paunang sanhi ng sunog sa pantry?","explanation_en":"The scenario explicitly mentions a \'recent issue with an overloaded extension cord\' and the presence of multiple electrical appliances, making faulty wiring or overloaded circuits the most likely initial cause of an electrical fire.","explanation_fil":"Malinaw na binanggit sa sitwasyon ang \'kamakailang isyu sa sobrang kargadong extension cord\' at ang pagkakaroon ng maraming electrical appliances, kaya\'t ang may depektong kable o sobrang kargadong sirkito ang pinakamalamang na paunang sanhi ng sunog na elektrikal.","choice_a_en":"Unattended cooking on the electric stove.","choice_a_fil":"Hindi binabantayang pagluluto sa electric stove.","choice_b_en":"Faulty wiring or an overloaded extension cord for the appliances.","choice_b_fil":"May depektong kable o sobrang kargadong extension cord para sa mga appliances.","choice_c_en":"A lit cigarette carelessly discarded.","choice_c_fil":"Isang nakasinding sigarilyo na pabayaang itinapon.","choice_d_en":"Spontaneous combustion of cleaning materials.","choice_d_fil":"Kusang pagliyab ng mga kagamitan sa paglilinis.","is_manual":false,"status":"published"},{"number":2,"competency":"emergency_response","correct_answer":"B","question_en":"What should be the IMMEDIATE first action of the LGU staff member upon noticing the smoke and crackling sound?","question_fil":"Ano ang DAPAT na AGARANG unang pagkilos ng kawani ng LGU kapag napansin ang usok at ugong ng pagliyab?","explanation_en":"The immediate priority in a developing fire with multiple occupants is to alert everyone and initiate evacuation, which activating an alarm and shouting \'Fire!\' accomplishes.","explanation_fil":"Ang agarang prayoridad sa isang lumalalang sunog na may maraming taong naroroon ay alertuhin ang lahat at simulan ang paglikas, na matutupad sa pag-aktiba ng alarma at pagsigaw ng \'Sunog!\'.","choice_a_en":"Grab the nearest fire extinguisher and attempt to put out the fire alone.","choice_a_fil":"Sunggaban ang pinakamalapit na fire extinguisher at subukang apulahin ang apoy nang mag-isa.","choice_b_en":"Activate the fire alarm (if available) and shout \'Fire! Evacuate!\' to alert everyone.","choice_b_fil":"I-aktiba ang fire alarm (kung mayroon) at sumigaw ng \'Sunog! Lumikas!\' upang alertuhin ang lahat.","choice_c_en":"Rush to the pantry to investigate the exact source of the fire.","choice_c_fil":"Magmadali patungo sa pantry upang imbestigahan ang eksaktong pinagmulan ng apoy.","choice_d_en":"Call the barangay captain for instructions.","choice_d_fil":"Tumawag sa kapitan ng barangay para sa mga tagubilin.","is_manual":false,"status":"published"},{"number":3,"competency":"knowledge","correct_answer":"B","question_en":"The ABC dry chemical extinguisher is mentioned. What types of fires is an ABC extinguisher effective against?","question_fil":"Binanggit ang ABC dry chemical extinguisher. Anong uri ng sunog ang epektibong apulahin ng isang ABC extinguisher?","explanation_en":"An ABC dry chemical extinguisher is designed to be effective against Class A (wood, paper), Class B (flammable liquids), and Class C (electrical) fires, making it versatile for general use.","explanation_fil":"Ang isang ABC dry chemical extinguisher ay idinisenyo upang maging epektibo laban sa mga sunog na Class A (kahoy, papel), Class B (mga likidong madaling magliyab), at Class C (elektrikal), na ginagawa itong versatile para sa pangkalahatang paggamit.","choice_a_en":"Only Class A (ordinary combustibles) fires.","choice_a_fil":"Mga sunog lamang na Class A (karaniwang nasusunog na materyales).","choice_b_en":"Class A (ordinary combustibles), Class B (flammable liquids), and Class C (electrical) fires.","choice_b_fil":"Mga sunog na Class A (karaniwang nasusunog na materyales), Class B (mga likidong madaling magliyab), at Class C (elektrikal).","choice_c_en":"Class B (flammable liquids) and Class C (electrical) fires only.","choice_c_fil":"Mga sunog lamang na Class B (mga likidong madaling magliyab) at Class C (elektrikal).","choice_d_en":"Class K (cooking oils) fires only.","choice_d_fil":"Mga sunog lamang na Class K (mantika sa pagluluto).","is_manual":false,"status":"published"},{"number":4,"competency":"decision_making","correct_answer":"C","question_en":"Given the \'growing smoke\' and \'panic\' among 50 participants, when is it appropriate for an LGU staff member to attempt to use a fire extinguisher?","question_fil":"Dahil sa \'lumalalang usok\' at \'takot\' sa humigit-kumulang 50 kalahok, kailan ang angkop na panahon para sa isang kawani ng LGU na subukang gumamit ng fire extinguisher?","explanation_en":"The decision to use an extinguisher should only be made if the fire is small, contained, there\'s a clear escape route, and most importantly, primary evacuation efforts are already in progress. Personal safety is paramount.","explanation_fil":"Ang desisyon na gumamit ng extinguisher ay dapat lamang gawin kung ang sunog ay maliit, nakakulong, may malinaw na daanan ng pagtakas, at higit sa lahat, isinasagawa na ang mga pangunahing pagsisikap sa paglikas. Ang personal na kaligtasan ang pinakamahalaga.","choice_a_en":"Immediately, as long as an extinguisher is available.","choice_a_fil":"Agad-agad, basta\'t may fire extinguisher na magagamit.","choice_b_en":"Only after everyone has evacuated and the fire department has been called.","choice_b_fil":"Pagkatapos lamang na makalikas ang lahat at natawagan na ang bumbero.","choice_c_en":"If the fire is small, contained, safe to approach, and evacuation is already underway.","choice_c_fil":"Kung ang apoy ay maliit, nakakulong, ligtas lapitan, at nagsisimula na ang paglikas.","choice_d_en":"Never, as fire suppression is solely the job of professional firefighters.","choice_d_fil":"Huwag kailanman, dahil ang pagpatay ng sunog ay trabaho lamang ng mga propesyonal na bumbero.","is_manual":false,"status":"published"},{"number":5,"competency":"safety_awareness","correct_answer":"B","question_en":"To prevent future electrical fires in the multi-purpose hall pantry, what fire prevention practice should be immediately implemented?","question_fil":"Upang maiwasan ang mga sunog na elektrikal sa hinaharap sa pantry ng multi-purpose hall, anong kasanayan sa pag-iwas sa sunog ang dapat agarang ipatupad?","explanation_en":"Based on the scenario\'s hint of an overloaded extension cord, ensuring proper electrical safety through inspection and avoiding overloading is a critical fire prevention practice.","explanation_fil":"Batay sa pahiwatig ng sitwasyon tungkol sa sobrang kargadong extension cord, ang pagtiyak ng wastong kaligtasan sa kuryente sa pamamagitan ng inspeksyon at pag-iwas sa sobrang karga ay isang kritikal na kasanayan sa pag-iwas sa sunog.","choice_a_en":"Place fire extinguishers inside the pantry.","choice_a_fil":"Maglagay ng mga fire extinguisher sa loob ng pantry.","choice_b_en":"Ensure extension cords are not overloaded and regularly inspect electrical wiring and appliances.","choice_b_fil":"Siguraduhin na ang mga extension cord ay hindi sobrang kargado at regular na suriin ang mga kable ng kuryente at appliances.","choice_c_en":"Prohibit the use of any electrical appliances in the pantry.","choice_c_fil":"Ipagbawal ang paggamit ng anumang electrical appliance sa pantry.","choice_d_en":"Install smoke detectors that are not connected to power outlets.","choice_d_fil":"Mag-install ng mga smoke detector na hindi nakakonekta sa mga saksakan ng kuryente.","is_manual":false,"status":"published"},{"number":6,"competency":"emergency_response","correct_answer":"C","question_en":"After activating the alarm and initiating evacuation, what is the next critical step for the LGU staff?","question_fil":"Pagkatapos i-aktiba ang alarma at simulan ang paglikas, ano ang susunod na kritikal na hakbang para sa kawani ng LGU?","explanation_en":"After initial alert and evacuation, contacting professional emergency services like the BFP is paramount to ensure a rapid and effective professional response.","explanation_fil":"Pagkatapos ng paunang alerto at paglikas, ang pagtawag sa mga propesyonal na serbisyong pang-emergency tulad ng BFP ay napakahalaga upang matiyak ang mabilis at epektibong propesyonal na tugon.","choice_a_en":"Attempt to cut off the main power supply to the building.","choice_a_fil":"Subukang putulin ang pangunahing suplay ng kuryente sa gusali.","choice_b_en":"Conduct a headcount of all participants inside the hall.","choice_b_fil":"Magsagawa ng headcount ng lahat ng kalahok sa loob ng bulwagan.","choice_c_en":"Call the local fire department (BFP) and provide precise details of the incident.","choice_c_fil":"Tumawag sa lokal na kagawaran ng bumbero (BFP) at magbigay ng tumpak na detalye ng insidente.","choice_d_en":"Direct everyone to a different part of the building away from the fire.","choice_d_fil":"Idirekta ang lahat sa ibang bahagi ng gusali na malayo sa sunog.","is_manual":false,"status":"published"},{"number":7,"competency":"knowledge","correct_answer":"B","question_en":"What is the primary principle of fire safety often referred to as the \'Fire Triangle\'?","question_fil":"Ano ang pangunahing prinsipyo ng kaligtasan sa sunog na madalas tinutukoy bilang \'Tatsulok ng Apoy\' (Fire Triangle)?","explanation_en":"The Fire Triangle consists of three elements necessary for a fire to start and sustain: Fuel, Heat, and Oxygen.","explanation_fil":"Ang Tatsulok ng Apoy ay binubuo ng tatlong elemento na kinakailangan upang magsimula at magpatuloy ang sunog: Panggatong, Init, at Oxygen.","choice_a_en":"Heat, Oxygen, Smoke.","choice_a_fil":"Init, Oxygen, Usok.","choice_b_en":"Fuel, Heat, Oxygen.","choice_b_fil":"Panggatong, Init, Oxygen.","choice_c_en":"Ignition, Flame, Extinguisher.","choice_c_fil":"Pagliyab, Apoy, Extinguisher.","choice_d_en":"Alarm, Evacuate, Call.","choice_d_fil":"Alarma, Lumikas, Tumawag.","is_manual":false,"status":"published"},{"number":8,"competency":"decision_making","correct_answer":"C","question_en":"The main exit is partially blocked by panicked individuals. What is the most effective approach for the LGU staff to manage this situation during evacuation?","question_fil":"Ang pangunahing labasan ay bahagyang nahaharangan ng mga indibidwal na natataranta. Ano ang pinakaepektibong paraan para sa kawani ng LGU na pamahalaan ang sitwasyong ito sa panahon ng paglikas?","explanation_en":"In a panic situation, calm and clear communication, along with directing people to available alternative exits, is crucial for effective crowd management and safe evacuation.","explanation_fil":"Sa isang sitwasyon ng takot, ang kalmado at malinaw na komunikasyon, kasama ang pagdidirekta ng mga tao sa mga magagamit na alternatibong labasan, ay mahalaga para sa epektibong pamamahala ng maraming tao at ligtas na paglikas.","choice_a_en":"Push through the crowd to clear the exit quickly.","choice_a_fil":"Itulak ang maraming tao upang mabilis na malinis ang labasan.","choice_b_en":"Shout loudly to create more panic and make people move.","choice_b_fil":"Sumigaw nang malakas upang lumikha ng mas matinding takot at paalisin ang mga tao.","choice_c_en":"Calmly direct people to alternative exits and provide clear, reassuring instructions.","choice_c_fil":"Mahinahong idirekta ang mga tao sa mga alternatibong labasan at magbigay ng malinaw at nakakapanatag na tagubilin.","choice_d_en":"Wait for the fire department to arrive and manage the crowd.","choice_d_fil":"Hintayin ang pagdating ng bumbero upang pamahalaan ang maraming tao.","is_manual":false,"status":"published"},{"number":9,"competency":"safety_awareness","correct_answer":"B","question_en":"What immediate fire prevention measure could have potentially averted the pantry fire, considering the \'overloaded extension cord\' concern?","question_fil":"Anong agarang hakbang sa pag-iwas sa sunog ang maaaring nakapigil sa sunog sa pantry, kung isasaalang-alang ang isyu ng \'sobrang kargadong extension cord\'?","explanation_en":"Overloaded extension cords are a common cause of electrical fires. Ensuring proper wattage and not overloading circuits are direct preventive measures.","explanation_fil":"Ang sobrang kargadong extension cord ay karaniwang sanhi ng mga sunog na elektrikal. Ang pagtiyak ng wastong wattage at hindi pagsobra sa karga ng mga sirkito ay mga direktang hakbang sa pag-iwas.","choice_a_en":"Regularly testing the smoke detectors in the hall.","choice_a_fil":"Regular na pagsubok sa mga smoke detector sa bulwagan.","choice_b_en":"Ensuring proper wattage for appliances and avoiding multiple high-power devices on one extension.","choice_b_fil":"Pagtitiyak ng wastong wattage para sa mga appliances at pag-iwas sa maraming high-power device sa isang extension.","choice_c_en":"Keeping flammable liquids away from electrical outlets.","choice_c_fil":"Paglalayo ng mga madaling magliyab na likido mula sa mga saksakan ng kuryente.","choice_d_en":"Training all occupants on how to use a fire extinguisher.","choice_d_fil":"Pagsasanay sa lahat ng nakatira kung paano gumamit ng fire extinguisher.","is_manual":false,"status":"published"},{"number":10,"competency":"emergency_response","correct_answer":"B","question_en":"When evacuating the hall, what should be the primary instruction for the participants regarding their personal belongings?","question_fil":"Kapag lumilikas mula sa bulwagan, ano ang pangunahing tagubilin para sa mga kalahok tungkol sa kanilang personal na gamit?","explanation_en":"During an emergency evacuation, personal safety is paramount. Time should not be wasted gathering belongings, as it can impede evacuation and put lives at risk.","explanation_fil":"Sa panahon ng emergency evacuation, ang personal na kaligtasan ang pinakamahalaga. Hindi dapat sayangin ang oras sa pagkuha ng mga gamit, dahil maaari itong makahadlang sa paglikas at maglagay ng buhay sa panganib.","choice_a_en":"Gather all personal belongings quickly before exiting.","choice_a_fil":"Kolektahin ang lahat ng personal na gamit nang mabilis bago lumabas.","choice_b_en":"Leave all personal belongings behind and proceed directly to the assembly point.","choice_b_fil":"Iwanan ang lahat ng personal na gamit at dumiretso sa assembly point.","choice_c_en":"Only take valuable items that are easily accessible.","choice_c_fil":"Kunin lamang ang mahahalagang gamit na madaling abutin.","choice_d_en":"Send one person to collect everyone\'s belongings.","choice_d_fil":"Magpadala ng isang tao upang kolektahin ang gamit ng lahat.","is_manual":false,"status":"published"},{"number":11,"competency":"knowledge","correct_answer":"B","question_en":"The older CO2 extinguisher is near the stage. What class of fires is a CO2 extinguisher primarily recommended for?","question_fil":"Ang mas lumang CO2 extinguisher ay malapit sa entablado. Anong klase ng sunog ang pangunahing inirerekomenda para sa isang CO2 extinguisher?","explanation_en":"CO2 (Carbon Dioxide) extinguishers are most effective against Class B (flammable liquids) and Class C (electrical) fires because they displace oxygen and leave no residue.","explanation_fil":"Ang CO2 (Carbon Dioxide) extinguisher ay pinakaepektibo laban sa mga sunog na Class B (mga likidong madaling magliyab) at Class C (elektrikal) dahil pinalalayas nito ang oxygen at hindi nag-iiwan ng anumang residue.","choice_a_en":"Class A (ordinary combustibles) and Class K (cooking oils).","choice_a_fil":"Class A (karaniwang nasusunog na materyales) at Class K (mantika sa pagluluto).","choice_b_en":"Class B (flammable liquids) and Class C (electrical).","choice_b_fil":"Class B (mga likidong madaling magliyab) at Class C (elektrikal).","choice_c_en":"Class A (ordinary combustibles) only.","choice_c_fil":"Class A (karaniwang nasusunog na materyales) lamang.","choice_d_en":"All types of fires including metal fires.","choice_d_fil":"Lahat ng uri ng sunog kabilang ang sunog ng metal.","is_manual":false,"status":"published"},{"number":12,"competency":"decision_making","correct_answer":"B","question_en":"If an LGU staff member decides to use the ABC dry chemical extinguisher, what is the correct technique to operate it?","question_fil":"Kung magpasya ang isang kawani ng LGU na gamitin ang ABC dry chemical extinguisher, ano ang tamang pamamaraan upang paandarin ito?","explanation_en":"The proper technique for operating a fire extinguisher is PASS: Pull the pin, Aim at the base of the fire, Squeeze the handle, and Sweep side to side.","explanation_fil":"Ang tamang pamamaraan sa pagpapatakbo ng fire extinguisher ay PASS: Hilahin ang pin (Pull the pin), Itutok sa ilalim ng apoy (Aim at the base), Pisilin ang hawakan (Squeeze the handle), at Igulong mula sa gilid patungo sa gilid (Sweep side to side).","choice_a_en":"Aim at the flames, Sweep side to side, Pull the pin, Squeeze the handle (ASPS).","choice_a_fil":"Itutok sa apoy, Igulong mula sa gilid patungo sa gilid, Hilahin ang pin, Pisilin ang hawakan (ASPS).","choice_b_en":"Pull the pin, Aim at the base, Squeeze the handle, Sweep side to side (PASS).","choice_b_fil":"Hilahin ang pin, Itutok sa ilalim, Pisilin ang hawakan, Igulong mula sa gilid patungo sa gilid (PASS).","choice_c_en":"Squeeze the handle, Aim at the top, Pull the pin, Sweep up and down (SAPS).","choice_c_fil":"Pisilin ang hawakan, Itutok sa itaas, Hilahin ang pin, Igulong pataas at pababa (SAPS).","choice_d_en":"Push the lever, Activate the nozzle, Spray until empty, Stop (PASS is for CO2 only).","choice_d_fil":"Itulak ang lever, Aktibahin ang nozzle, I-spray hanggang maubos, Huminto (Ang PASS ay para lamang sa CO2).","is_manual":false,"status":"published"},{"number":13,"competency":"safety_awareness","correct_answer":"B","question_en":"After evacuating the building, where should all participants and staff gather?","question_fil":"Pagkatapos lumikas mula sa gusali, saan dapat magtipon ang lahat ng kalahok at kawani?","explanation_en":"A designated assembly point is crucial for accountability and ensuring everyone is safely away from the danger zone, facilitating headcounts.","explanation_fil":"Ang isang itinalagang lugar ng pagtitipon ay mahalaga para sa pananagutan at pagtiyak na ligtas ang lahat mula sa sona ng panganib, na nagpapadali sa pagbibilang ng tao.","choice_a_en":"Immediately outside the burning building to observe.","choice_a_fil":"Agad sa labas ng nasusunog na gusali upang obserbahan.","choice_b_en":"A pre-designated safe assembly point away from the building.","choice_b_fil":"Isang pre-designated na ligtas na lugar ng pagtitipon na malayo sa gusali.","choice_c_en":"The barangay hall nearby to wait for instructions.","choice_c_fil":"Ang barangay hall na malapit upang maghintay ng tagubilin.","choice_d_en":"Anywhere they feel safe, as long as it\'s outside.","choice_d_fil":"Kahit saan sila nakakaramdam ng kaligtasan, basta nasa labas.","is_manual":false,"status":"published"},{"number":14,"competency":"emergency_response","correct_answer":"B","question_en":"What is the crucial information to relay when calling the local fire department (BFP)?","question_fil":"Ano ang mahalagang impormasyon na dapat ipaabot kapag tumatawag sa lokal na kagawaran ng bumbero (BFP)?","explanation_en":"Providing clear, concise, and comprehensive information including the address, nature of the emergency, number of people, and hazards helps the BFP respond effectively.","explanation_fil":"Ang pagbibigay ng malinaw, tumpak, at komprehensibong impormasyon kabilang ang address, uri ng emerhensiya, bilang ng mga tao, at mga panganib ay nakakatulong sa BFP na tumugon nang epektibo.","choice_a_en":"Only the type of fire extinguisher available.","choice_a_fil":"Ang uri lamang ng fire extinguisher na magagamit.","choice_b_en":"Exact address, nature of the emergency, number of people involved, and any known hazards.","choice_b_fil":"Eksaktong address, uri ng emerhensiya, bilang ng mga taong sangkot, at anumang alam na panganib.","choice_c_en":"Only the number of people injured.","choice_c_fil":"Ang bilang lamang ng mga nasugatan.","choice_d_en":"The weather conditions at the time of the fire.","choice_d_fil":"Ang kalagayan ng panahon sa oras ng sunog.","is_manual":false,"status":"published"},{"number":15,"competency":"knowledge","correct_answer":"B","question_en":"What does it mean for a fire to be \'contained\' when considering using a fire extinguisher?","question_fil":"Ano ang ibig sabihin ng isang sunog na \'nakakulong\' (contained) kapag isinasaalang-alang ang paggamit ng fire extinguisher?","explanation_en":"A contained fire is one that is confined to a very small area and has not yet spread, making it potentially manageable with a portable extinguisher.","explanation_fil":"Ang nakakulong na sunog ay isa na limitado sa isang napakaliit na lugar at hindi pa kumalat, na ginagawa itong posibleng mapamahalaan gamit ang isang portable extinguisher.","choice_a_en":"The fire has spread to multiple rooms.","choice_a_fil":"Kumalat na ang sunog sa maraming silid.","choice_b_en":"The fire is limited to a small, isolated area, like a wastebasket or small appliance.","choice_b_fil":"Ang sunog ay limitado sa isang maliit, nakahiwalay na lugar, tulad ng basurahan o maliit na appliance.","choice_c_en":"The fire is producing a lot of smoke but no flames.","choice_c_fil":"Ang sunog ay naglalabas ng maraming usok ngunit walang apoy.","choice_d_en":"The fire is actively growing larger but still visible.","choice_d_fil":"Aktibong lumalaki ang sunog ngunit nakikita pa rin.","is_manual":false,"status":"published"},{"number":16,"competency":"decision_making","correct_answer":"C","question_en":"If after a brief attempt, the fire in the pantry does NOT immediately diminish, what should the LGU staff member do?","question_fil":"Kung pagkatapos ng maikling pagsubok, ang sunog sa pantry ay HINDI agad nabawasan, ano ang dapat gawin ng kawani ng LGU?","explanation_en":"If a fire doesn\'t respond quickly to an extinguisher, it\'s safer to abandon the attempt, ensure the door is closed (to contain smoke and fire), and prioritize complete evacuation. Personal safety always comes first.","explanation_fil":"Kung ang isang sunog ay hindi mabilis na tumugon sa isang extinguisher, mas ligtas na talikdan ang pagtatangka, tiyakin na nakasara ang pinto (upang makulong ang usok at apoy), at bigyang-prayoridad ang kumpletong paglikas. Laging nauuna ang personal na kaligtasan.","choice_a_en":"Continue fighting the fire until the extinguisher is empty.","choice_a_fil":"Patuloy na labanan ang apoy hanggang maubos ang extinguisher.","choice_b_en":"Get another extinguisher and try again.","choice_b_fil":"Kumuha ng isa pang extinguisher at subukang muli.","choice_c_en":"Immediately abandon the attempt, close the door (if safe), and prioritize full evacuation.","choice_c_fil":"Agad na talikdan ang pagtatangka, isara ang pinto (kung ligtas), at bigyang-prayoridad ang kumpletong paglikas.","choice_d_en":"Wait for the fire to reduce in size naturally.","choice_d_fil":"Hintayin na natural na lumiit ang apoy.","is_manual":false,"status":"published"},{"number":17,"competency":"safety_awareness","correct_answer":"C","question_en":"During the evacuation, if a participant\'s clothing catches fire, what is the most appropriate instruction to give them?","question_fil":"Sa panahon ng paglikas, kung nasunog ang damit ng isang kalahok, ano ang pinakaangkop na tagubilin na ibibigay sa kanila?","explanation_en":"\'Stop, Drop, and Roll\' is the internationally recognized and most effective method to extinguish flames on a person\'s clothing.","explanation_fil":"Ang \'Huminto, Dumapa, at Gumulong\' (Stop, Drop, and Roll) ay ang pandaigdigang kinikilala at pinakaepektibong paraan upang patayin ang apoy sa damit ng isang tao.","choice_a_en":"Run towards the exit as fast as possible.","choice_a_fil":"Tumakbo patungo sa labasan nang mabilis hangga\'t maaari.","choice_b_en":"Pat the fire out with their hands.","choice_b_fil":"Palayain ang apoy gamit ang kanilang mga kamay.","choice_c_en":"Stop, Drop, and Roll.","choice_c_fil":"Huminto, Dumapa, at Gumulong (Stop, Drop, and Roll).","choice_d_en":"Remove the burning clothing immediately.","choice_d_fil":"Tanggalin agad ang nasusunog na damit.","is_manual":false,"status":"published"},{"number":18,"competency":"emergency_response","correct_answer":"B","question_en":"Upon arrival at the assembly point, what is the primary responsibility of the LGU staff member in charge?","question_fil":"Pagdating sa assembly point, ano ang pangunahing responsibilidad ng kawani ng LGU na namamahala?","explanation_en":"Accountability is critical post-evacuation. A headcount helps determine if everyone safely evacuated and alerts emergency responders if anyone is still inside.","explanation_fil":"Ang pananagutan ay kritikal pagkatapos ng paglikas. Nakakatulong ang headcount upang matukoy kung ligtas na nakalikas ang lahat at alertuhin ang mga emergency responder kung mayroon pa ring nasa loob.","choice_a_en":"Contact relatives of the participants.","choice_a_fil":"Makipag-ugnayan sa mga kamag-anak ng mga kalahok.","choice_b_en":"Perform a headcount and report any missing individuals to the BFP.","choice_b_fil":"Magsagawa ng headcount at iulat ang sinumang nawawalang indibidwal sa BFP.","choice_c_en":"Go back inside the building to check for missing items.","choice_c_fil":"Bumalik sa loob ng gusali upang tingnan kung may nawawalang gamit.","choice_d_en":"Debrief the participants about the fire causes.","choice_d_fil":"I-debrief ang mga kalahok tungkol sa mga sanhi ng sunog.","is_manual":false,"status":"published"},{"number":19,"competency":"knowledge","correct_answer":"D","question_en":"Which of the following is NOT a common cause of fire incidents according to fire safety principles?","question_fil":"Alin sa mga sumusunod ang HINDI karaniwang sanhi ng mga insidente ng sunog ayon sa mga prinsipyo ng kaligtasan sa sunog?","explanation_en":"Well-maintained fire extinguishers are a fire *safety device*, not a cause of fire. The other options are recognized common causes.","explanation_fil":"Ang maayos na inaalagaan na mga fire extinguisher ay isang kagamitan para sa *kaligtasan sa sunog*, hindi sanhi ng sunog. Ang iba pang mga opsyon ay kinikilalang karaniwang sanhi.","choice_a_en":"Electrical overloading.","choice_a_fil":"Sobrang karga ng kuryente.","choice_b_en":"Unattended cooking.","choice_b_fil":"Hindi binabantayang pagluluto.","choice_c_en":"Improper storage of flammable materials.","choice_c_fil":"Hindi wastong pagtabi ng mga madaling magliyab na materyales.","choice_d_en":"Well-maintained and regularly inspected fire extinguishers.","choice_d_fil":"Maayos na inaalagaan at regular na iniinspeksyon na mga fire extinguisher.","is_manual":false,"status":"published"},{"number":20,"competency":"decision_making","correct_answer":"B","question_en":"An LGU staff member observes that the smoke from the pantry is now thick and dark, and visibility is severely reduced. What is the most appropriate decision regarding any attempt to suppress the fire?","question_fil":"Napansin ng isang kawani ng LGU na ang usok mula sa pantry ay makapal na at madilim, at lubhang nabawasan ang visibility. Ano ang pinakaangkop na desisyon tungkol sa anumang pagtatangka na apulahin ang apoy?","explanation_en":"Thick, dark smoke and reduced visibility indicate a rapidly escalating and dangerous fire. At this point, personal safety and ensuring everyone\'s evacuation take absolute precedence over any attempt at fire suppression by untrained personnel.","explanation_fil":"Ang makapal, madilim na usok at nabawasang visibility ay nagpapahiwatig ng mabilis na lumalala at mapanganib na sunog. Sa puntong ito, ang personal na kaligtasan at pagtiyak sa paglikas ng lahat ay ganap na mas mahalaga kaysa sa anumang pagtatangka na apulahin ang sunog ng mga hindi sinanay na tauhan.","choice_a_en":"Proceed with caution, as long as an extinguisher is still nearby.","choice_a_fil":"Magpatuloy nang maingat, basta\'t malapit pa rin ang extinguisher.","choice_b_en":"Abandon any fire suppression efforts immediately and focus solely on safe evacuation.","choice_b_fil":"Agad na talikdan ang anumang pagtatangka sa pagpatay ng sunog at tumutok lamang sa ligtas na paglikas.","choice_c_en":"Attempt to ventilate the area before using the extinguisher.","choice_c_fil":"Subukang i-ventilate ang lugar bago gamitin ang extinguisher.","choice_d_en":"Wait for the smoke to clear slightly before approaching.","choice_d_fil":"Hintayin na bahagyang luminaw ang usok bago lumapit.","is_manual":false,"status":"published"},{"question_en":"New scenario question","choice_a_en":"Option A","choice_b_en":"Option B","choice_c_en":"Option C","choice_d_en":"Option D","correct_answer":"A","explanation_en":"","competency":"knowledge","question_fil":"","explanation_fil":"","choice_a_fil":"","choice_b_fil":"","choice_c_fil":"","choice_d_fil":"","number":21,"is_manual":true,"status":"published"}]', 'en', 'AI Generated', NULL, NULL, 3, '2026-07-16 11:48:10', '2026-07-16 11:48:10', 3, 3, '2026-07-16 11:38:36', '2026-07-10 03:34:54', '2026-07-16 11:48:10');
REPLACE INTO `ai_scenario_configs` (`id`, `training_module_id`, `difficulty`, `number_of_questions`, `bank_question_count`, `quiz_question_count`, `generation_language`, `generated_language`, `time_limit_minutes`, `max_attempts`, `passing_score`, `fail_retake_policy`, `auto_submit_on_expire`, `allow_resume_attempt`, `shuffle_questions`, `shuffle_answer_choices`, `current_version_id`, `published_version_id`, `is_enabled`, `scenario_title`, `title_en`, `title_fil`, `generated_scenario`, `description_en`, `description_fil`, `learning_objectives_en`, `learning_objectives_fil`, `generated_questions`, `generated_at`, `translated_at`, `created_by`, `created_at`, `updated_at`) VALUES
	(1, 5, 'medium', 30, 30, 30, 'en', 'en', 30, 5, 50, 'quiz_retake_only', 1, 1, 1, 1, 1, 1, 1, 'Fire Incident at Barangay Multi-Purpose Hall', 'Fire Incident at Barangay Multi-Purpose Hall', 'Insidente ng Sunog sa Barangay Multi-Purpose Hall', 'It\'s a busy Monday morning at the Barangay Maharlika Multi-Purpose Hall. The hall, frequently used for community meetings, LGU outreach programs, and as a temporary evacuation center, is currently hosting a livelihood training seminar for local women. Approximately 50 participants, along with five LGU staff members, are present. Suddenly, a strong burning smell fills the air, originating from the small pantry area adjacent to the main hall, where a refrigerator, microwave, and an electric kettle are located. Smoke begins to visibly emanate from the pantry door, and a low crackling sound can be heard. Some participants recall a recent issue with an overloaded extension cord in the pantry that was never fully addressed.\n\nPanic starts to spread among the participants, some of whom are blocking the main exit in their confusion. An LGU staff member quickly identifies the smoke source and realizes the situation is escalating. There are two fire extinguishers visible in the main hall: a red ABC dry chemical extinguisher mounted near the entrance, and a smaller, older CO2 extinguisher near the stage. The LGU staff are trained in basic fire safety, but the number of people and the growing smoke present a significant challenge for emergency response and evacuation.', 'It\'s a busy Monday morning at the Barangay Maharlika Multi-Purpose Hall. The hall, frequently used for community meetings, LGU outreach programs, and as a temporary evacuation center, is currently hosting a livelihood training seminar for local women. Approximately 50 participants, along with five LGU staff members, are present. Suddenly, a strong burning smell fills the air, originating from the small pantry area adjacent to the main hall, where a refrigerator, microwave, and an electric kettle are located. Smoke begins to visibly emanate from the pantry door, and a low crackling sound can be heard. Some participants recall a recent issue with an overloaded extension cord in the pantry that was never fully addressed.\n\nPanic starts to spread among the participants, some of whom are blocking the main exit in their confusion. An LGU staff member quickly identifies the smoke source and realizes the situation is escalating. There are two fire extinguishers visible in the main hall: a red ABC dry chemical extinguisher mounted near the entrance, and a smaller, older CO2 extinguisher near the stage. The LGU staff are trained in basic fire safety, but the number of people and the growing smoke present a significant challenge for emergency response and evacuation.', 'Abalang umaga ng Lunes sa Barangay Maharlika Multi-Purpose Hall. Ang bulwagan, na madalas gamitin para sa mga pagpupulong ng komunidad, mga programang outreach ng LGU, at bilang pansamantalang sentro ng paglikas, ay kasalukuyang nagho-host ng seminar sa pagsasanay sa pangkabuhayan para sa mga kababaihan sa lokalidad. Humigit-kumulang 50 kalahok, kasama ang limang kawani ng LGU, ang naroroon. Bigla, isang matinding amoy ng sunog ang kumalat sa hangin, na nagmula sa maliit na pantry na katabi ng pangunahing bulwagan, kung saan matatagpuan ang isang refrigerator, microwave, at electric kettle. Nagsisimulang makita ang usok na lumalabas mula sa pinto ng pantry, at isang mahina na ugong ng pagliyab ang naririnig. Naaalala ng ilang kalahok ang isang kamakailang isyu sa sobrang kargadong extension cord sa pantry na hindi lubos na natugunan.\n\nNagsimulang kumalat ang takot sa mga kalahok, kung saan ang ilan ay humaharang sa pangunahing labasan dahil sa pagkalito. Mabilis na natukoy ng isang kawani ng LGU ang pinagmulan ng usok at napagtanto na lumalala ang sitwasyon. Mayroong dalawang fire extinguisher na nakikita sa pangunahing bulwagan: isang pulang ABC dry chemical extinguisher na nakasabit malapit sa pasukan, at isang mas maliit, at mas lumang CO2 extinguisher malapit sa entablado. Ang mga kawani ng LGU ay sinanay sa pangunahing kaligtasan sa sunog, ngunit ang dami ng tao at ang lumalalang usok ay nagpapakita ng malaking hamon para sa tugon sa emerhensiya at paglikas.', 'To evaluate participants\' ability to identify common fire hazards and apply fire prevention practices in public facilities.\nTo assess understanding of immediate emergency response protocols during a fire incident, including alarm activation and calling for help.\nTo test participants\' decision-making regarding the safe use of fire extinguishers versus prioritizing evacuation in a developing fire scenario.\nTo reinforce the importance of proper evacuation procedures and crowd management during an emergency for diverse groups.\nTo measure knowledge of the types of fire extinguishers and their appropriate applications.', 'Upang suriin ang kakayahan ng mga kalahok na matukoy ang mga karaniwang panganib sa sunog at mailapat ang mga kasanayan sa pag-iwas sa sunog sa mga pampublikong pasilidad.\nUpang matasa ang pag-unawa sa mga agarang protocol ng pagtugon sa emerhensiya sa panahon ng insidente ng sunog, kabilang ang pag-aktiba ng alarma at pagtawag para sa tulong.\nUpang subukan ang paggawa ng desisyon ng mga kalahok tungkol sa ligtas na paggamit ng fire extinguisher kumpara sa pagbibigay-prayoridad sa paglikas sa isang lumalalang sitwasyon ng sunog.\nUpang bigyang-diin ang kahalagahan ng wastong pamamaraan ng paglikas at pamamahala ng maraming tao sa panahon ng isang emerhensiya para sa iba\'t ibang grupo.\nUpang sukatin ang kaalaman tungkol sa mga uri ng fire extinguisher at ang kanilang angkop na paggamit.', '[{"number":1,"competency":"safety_awareness","correct_answer":"B","question_en":"Based on the scenario, what is the most likely initial cause of the fire in the pantry?","question_fil":"Batay sa sitwasyon, ano ang pinakamalamang na paunang sanhi ng sunog sa pantry?","explanation_en":"The scenario explicitly mentions a \'recent issue with an overloaded extension cord\' and the presence of multiple electrical appliances, making faulty wiring or overloaded circuits the most likely initial cause of an electrical fire.","explanation_fil":"Malinaw na binanggit sa sitwasyon ang \'kamakailang isyu sa sobrang kargadong extension cord\' at ang pagkakaroon ng maraming electrical appliances, kaya\'t ang may depektong kable o sobrang kargadong sirkito ang pinakamalamang na paunang sanhi ng sunog na elektrikal.","choice_a_en":"Unattended cooking on the electric stove.","choice_a_fil":"Hindi binabantayang pagluluto sa electric stove.","choice_b_en":"Faulty wiring or an overloaded extension cord for the appliances.","choice_b_fil":"May depektong kable o sobrang kargadong extension cord para sa mga appliances.","choice_c_en":"A lit cigarette carelessly discarded.","choice_c_fil":"Isang nakasinding sigarilyo na pabayaang itinapon.","choice_d_en":"Spontaneous combustion of cleaning materials.","choice_d_fil":"Kusang pagliyab ng mga kagamitan sa paglilinis.","is_manual":false,"status":"published"},{"number":2,"competency":"emergency_response","correct_answer":"B","question_en":"What should be the IMMEDIATE first action of the LGU staff member upon noticing the smoke and crackling sound?","question_fil":"Ano ang DAPAT na AGARANG unang pagkilos ng kawani ng LGU kapag napansin ang usok at ugong ng pagliyab?","explanation_en":"The immediate priority in a developing fire with multiple occupants is to alert everyone and initiate evacuation, which activating an alarm and shouting \'Fire!\' accomplishes.","explanation_fil":"Ang agarang prayoridad sa isang lumalalang sunog na may maraming taong naroroon ay alertuhin ang lahat at simulan ang paglikas, na matutupad sa pag-aktiba ng alarma at pagsigaw ng \'Sunog!\'.","choice_a_en":"Grab the nearest fire extinguisher and attempt to put out the fire alone.","choice_a_fil":"Sunggaban ang pinakamalapit na fire extinguisher at subukang apulahin ang apoy nang mag-isa.","choice_b_en":"Activate the fire alarm (if available) and shout \'Fire! Evacuate!\' to alert everyone.","choice_b_fil":"I-aktiba ang fire alarm (kung mayroon) at sumigaw ng \'Sunog! Lumikas!\' upang alertuhin ang lahat.","choice_c_en":"Rush to the pantry to investigate the exact source of the fire.","choice_c_fil":"Magmadali patungo sa pantry upang imbestigahan ang eksaktong pinagmulan ng apoy.","choice_d_en":"Call the barangay captain for instructions.","choice_d_fil":"Tumawag sa kapitan ng barangay para sa mga tagubilin.","is_manual":false,"status":"published"},{"number":3,"competency":"knowledge","correct_answer":"B","question_en":"The ABC dry chemical extinguisher is mentioned. What types of fires is an ABC extinguisher effective against?","question_fil":"Binanggit ang ABC dry chemical extinguisher. Anong uri ng sunog ang epektibong apulahin ng isang ABC extinguisher?","explanation_en":"An ABC dry chemical extinguisher is designed to be effective against Class A (wood, paper), Class B (flammable liquids), and Class C (electrical) fires, making it versatile for general use.","explanation_fil":"Ang isang ABC dry chemical extinguisher ay idinisenyo upang maging epektibo laban sa mga sunog na Class A (kahoy, papel), Class B (mga likidong madaling magliyab), at Class C (elektrikal), na ginagawa itong versatile para sa pangkalahatang paggamit.","choice_a_en":"Only Class A (ordinary combustibles) fires.","choice_a_fil":"Mga sunog lamang na Class A (karaniwang nasusunog na materyales).","choice_b_en":"Class A (ordinary combustibles), Class B (flammable liquids), and Class C (electrical) fires.","choice_b_fil":"Mga sunog na Class A (karaniwang nasusunog na materyales), Class B (mga likidong madaling magliyab), at Class C (elektrikal).","choice_c_en":"Class B (flammable liquids) and Class C (electrical) fires only.","choice_c_fil":"Mga sunog lamang na Class B (mga likidong madaling magliyab) at Class C (elektrikal).","choice_d_en":"Class K (cooking oils) fires only.","choice_d_fil":"Mga sunog lamang na Class K (mantika sa pagluluto).","is_manual":false,"status":"published"},{"number":4,"competency":"decision_making","correct_answer":"C","question_en":"Given the \'growing smoke\' and \'panic\' among 50 participants, when is it appropriate for an LGU staff member to attempt to use a fire extinguisher?","question_fil":"Dahil sa \'lumalalang usok\' at \'takot\' sa humigit-kumulang 50 kalahok, kailan ang angkop na panahon para sa isang kawani ng LGU na subukang gumamit ng fire extinguisher?","explanation_en":"The decision to use an extinguisher should only be made if the fire is small, contained, there\'s a clear escape route, and most importantly, primary evacuation efforts are already in progress. Personal safety is paramount.","explanation_fil":"Ang desisyon na gumamit ng extinguisher ay dapat lamang gawin kung ang sunog ay maliit, nakakulong, may malinaw na daanan ng pagtakas, at higit sa lahat, isinasagawa na ang mga pangunahing pagsisikap sa paglikas. Ang personal na kaligtasan ang pinakamahalaga.","choice_a_en":"Immediately, as long as an extinguisher is available.","choice_a_fil":"Agad-agad, basta\'t may fire extinguisher na magagamit.","choice_b_en":"Only after everyone has evacuated and the fire department has been called.","choice_b_fil":"Pagkatapos lamang na makalikas ang lahat at natawagan na ang bumbero.","choice_c_en":"If the fire is small, contained, safe to approach, and evacuation is already underway.","choice_c_fil":"Kung ang apoy ay maliit, nakakulong, ligtas lapitan, at nagsisimula na ang paglikas.","choice_d_en":"Never, as fire suppression is solely the job of professional firefighters.","choice_d_fil":"Huwag kailanman, dahil ang pagpatay ng sunog ay trabaho lamang ng mga propesyonal na bumbero.","is_manual":false,"status":"published"},{"number":5,"competency":"safety_awareness","correct_answer":"B","question_en":"To prevent future electrical fires in the multi-purpose hall pantry, what fire prevention practice should be immediately implemented?","question_fil":"Upang maiwasan ang mga sunog na elektrikal sa hinaharap sa pantry ng multi-purpose hall, anong kasanayan sa pag-iwas sa sunog ang dapat agarang ipatupad?","explanation_en":"Based on the scenario\'s hint of an overloaded extension cord, ensuring proper electrical safety through inspection and avoiding overloading is a critical fire prevention practice.","explanation_fil":"Batay sa pahiwatig ng sitwasyon tungkol sa sobrang kargadong extension cord, ang pagtiyak ng wastong kaligtasan sa kuryente sa pamamagitan ng inspeksyon at pag-iwas sa sobrang karga ay isang kritikal na kasanayan sa pag-iwas sa sunog.","choice_a_en":"Place fire extinguishers inside the pantry.","choice_a_fil":"Maglagay ng mga fire extinguisher sa loob ng pantry.","choice_b_en":"Ensure extension cords are not overloaded and regularly inspect electrical wiring and appliances.","choice_b_fil":"Siguraduhin na ang mga extension cord ay hindi sobrang kargado at regular na suriin ang mga kable ng kuryente at appliances.","choice_c_en":"Prohibit the use of any electrical appliances in the pantry.","choice_c_fil":"Ipagbawal ang paggamit ng anumang electrical appliance sa pantry.","choice_d_en":"Install smoke detectors that are not connected to power outlets.","choice_d_fil":"Mag-install ng mga smoke detector na hindi nakakonekta sa mga saksakan ng kuryente.","is_manual":false,"status":"published"},{"number":6,"competency":"emergency_response","correct_answer":"C","question_en":"After activating the alarm and initiating evacuation, what is the next critical step for the LGU staff?","question_fil":"Pagkatapos i-aktiba ang alarma at simulan ang paglikas, ano ang susunod na kritikal na hakbang para sa kawani ng LGU?","explanation_en":"After initial alert and evacuation, contacting professional emergency services like the BFP is paramount to ensure a rapid and effective professional response.","explanation_fil":"Pagkatapos ng paunang alerto at paglikas, ang pagtawag sa mga propesyonal na serbisyong pang-emergency tulad ng BFP ay napakahalaga upang matiyak ang mabilis at epektibong propesyonal na tugon.","choice_a_en":"Attempt to cut off the main power supply to the building.","choice_a_fil":"Subukang putulin ang pangunahing suplay ng kuryente sa gusali.","choice_b_en":"Conduct a headcount of all participants inside the hall.","choice_b_fil":"Magsagawa ng headcount ng lahat ng kalahok sa loob ng bulwagan.","choice_c_en":"Call the local fire department (BFP) and provide precise details of the incident.","choice_c_fil":"Tumawag sa lokal na kagawaran ng bumbero (BFP) at magbigay ng tumpak na detalye ng insidente.","choice_d_en":"Direct everyone to a different part of the building away from the fire.","choice_d_fil":"Idirekta ang lahat sa ibang bahagi ng gusali na malayo sa sunog.","is_manual":false,"status":"published"},{"number":7,"competency":"knowledge","correct_answer":"B","question_en":"What is the primary principle of fire safety often referred to as the \'Fire Triangle\'?","question_fil":"Ano ang pangunahing prinsipyo ng kaligtasan sa sunog na madalas tinutukoy bilang \'Tatsulok ng Apoy\' (Fire Triangle)?","explanation_en":"The Fire Triangle consists of three elements necessary for a fire to start and sustain: Fuel, Heat, and Oxygen.","explanation_fil":"Ang Tatsulok ng Apoy ay binubuo ng tatlong elemento na kinakailangan upang magsimula at magpatuloy ang sunog: Panggatong, Init, at Oxygen.","choice_a_en":"Heat, Oxygen, Smoke.","choice_a_fil":"Init, Oxygen, Usok.","choice_b_en":"Fuel, Heat, Oxygen.","choice_b_fil":"Panggatong, Init, Oxygen.","choice_c_en":"Ignition, Flame, Extinguisher.","choice_c_fil":"Pagliyab, Apoy, Extinguisher.","choice_d_en":"Alarm, Evacuate, Call.","choice_d_fil":"Alarma, Lumikas, Tumawag.","is_manual":false,"status":"published"},{"number":8,"competency":"decision_making","correct_answer":"C","question_en":"The main exit is partially blocked by panicked individuals. What is the most effective approach for the LGU staff to manage this situation during evacuation?","question_fil":"Ang pangunahing labasan ay bahagyang nahaharangan ng mga indibidwal na natataranta. Ano ang pinakaepektibong paraan para sa kawani ng LGU na pamahalaan ang sitwasyong ito sa panahon ng paglikas?","explanation_en":"In a panic situation, calm and clear communication, along with directing people to available alternative exits, is crucial for effective crowd management and safe evacuation.","explanation_fil":"Sa isang sitwasyon ng takot, ang kalmado at malinaw na komunikasyon, kasama ang pagdidirekta ng mga tao sa mga magagamit na alternatibong labasan, ay mahalaga para sa epektibong pamamahala ng maraming tao at ligtas na paglikas.","choice_a_en":"Push through the crowd to clear the exit quickly.","choice_a_fil":"Itulak ang maraming tao upang mabilis na malinis ang labasan.","choice_b_en":"Shout loudly to create more panic and make people move.","choice_b_fil":"Sumigaw nang malakas upang lumikha ng mas matinding takot at paalisin ang mga tao.","choice_c_en":"Calmly direct people to alternative exits and provide clear, reassuring instructions.","choice_c_fil":"Mahinahong idirekta ang mga tao sa mga alternatibong labasan at magbigay ng malinaw at nakakapanatag na tagubilin.","choice_d_en":"Wait for the fire department to arrive and manage the crowd.","choice_d_fil":"Hintayin ang pagdating ng bumbero upang pamahalaan ang maraming tao.","is_manual":false,"status":"published"},{"number":9,"competency":"safety_awareness","correct_answer":"B","question_en":"What immediate fire prevention measure could have potentially averted the pantry fire, considering the \'overloaded extension cord\' concern?","question_fil":"Anong agarang hakbang sa pag-iwas sa sunog ang maaaring nakapigil sa sunog sa pantry, kung isasaalang-alang ang isyu ng \'sobrang kargadong extension cord\'?","explanation_en":"Overloaded extension cords are a common cause of electrical fires. Ensuring proper wattage and not overloading circuits are direct preventive measures.","explanation_fil":"Ang sobrang kargadong extension cord ay karaniwang sanhi ng mga sunog na elektrikal. Ang pagtiyak ng wastong wattage at hindi pagsobra sa karga ng mga sirkito ay mga direktang hakbang sa pag-iwas.","choice_a_en":"Regularly testing the smoke detectors in the hall.","choice_a_fil":"Regular na pagsubok sa mga smoke detector sa bulwagan.","choice_b_en":"Ensuring proper wattage for appliances and avoiding multiple high-power devices on one extension.","choice_b_fil":"Pagtitiyak ng wastong wattage para sa mga appliances at pag-iwas sa maraming high-power device sa isang extension.","choice_c_en":"Keeping flammable liquids away from electrical outlets.","choice_c_fil":"Paglalayo ng mga madaling magliyab na likido mula sa mga saksakan ng kuryente.","choice_d_en":"Training all occupants on how to use a fire extinguisher.","choice_d_fil":"Pagsasanay sa lahat ng nakatira kung paano gumamit ng fire extinguisher.","is_manual":false,"status":"published"},{"number":10,"competency":"emergency_response","correct_answer":"B","question_en":"When evacuating the hall, what should be the primary instruction for the participants regarding their personal belongings?","question_fil":"Kapag lumilikas mula sa bulwagan, ano ang pangunahing tagubilin para sa mga kalahok tungkol sa kanilang personal na gamit?","explanation_en":"During an emergency evacuation, personal safety is paramount. Time should not be wasted gathering belongings, as it can impede evacuation and put lives at risk.","explanation_fil":"Sa panahon ng emergency evacuation, ang personal na kaligtasan ang pinakamahalaga. Hindi dapat sayangin ang oras sa pagkuha ng mga gamit, dahil maaari itong makahadlang sa paglikas at maglagay ng buhay sa panganib.","choice_a_en":"Gather all personal belongings quickly before exiting.","choice_a_fil":"Kolektahin ang lahat ng personal na gamit nang mabilis bago lumabas.","choice_b_en":"Leave all personal belongings behind and proceed directly to the assembly point.","choice_b_fil":"Iwanan ang lahat ng personal na gamit at dumiretso sa assembly point.","choice_c_en":"Only take valuable items that are easily accessible.","choice_c_fil":"Kunin lamang ang mahahalagang gamit na madaling abutin.","choice_d_en":"Send one person to collect everyone\'s belongings.","choice_d_fil":"Magpadala ng isang tao upang kolektahin ang gamit ng lahat.","is_manual":false,"status":"published"},{"number":11,"competency":"knowledge","correct_answer":"B","question_en":"The older CO2 extinguisher is near the stage. What class of fires is a CO2 extinguisher primarily recommended for?","question_fil":"Ang mas lumang CO2 extinguisher ay malapit sa entablado. Anong klase ng sunog ang pangunahing inirerekomenda para sa isang CO2 extinguisher?","explanation_en":"CO2 (Carbon Dioxide) extinguishers are most effective against Class B (flammable liquids) and Class C (electrical) fires because they displace oxygen and leave no residue.","explanation_fil":"Ang CO2 (Carbon Dioxide) extinguisher ay pinakaepektibo laban sa mga sunog na Class B (mga likidong madaling magliyab) at Class C (elektrikal) dahil pinalalayas nito ang oxygen at hindi nag-iiwan ng anumang residue.","choice_a_en":"Class A (ordinary combustibles) and Class K (cooking oils).","choice_a_fil":"Class A (karaniwang nasusunog na materyales) at Class K (mantika sa pagluluto).","choice_b_en":"Class B (flammable liquids) and Class C (electrical).","choice_b_fil":"Class B (mga likidong madaling magliyab) at Class C (elektrikal).","choice_c_en":"Class A (ordinary combustibles) only.","choice_c_fil":"Class A (karaniwang nasusunog na materyales) lamang.","choice_d_en":"All types of fires including metal fires.","choice_d_fil":"Lahat ng uri ng sunog kabilang ang sunog ng metal.","is_manual":false,"status":"published"},{"number":12,"competency":"decision_making","correct_answer":"B","question_en":"If an LGU staff member decides to use the ABC dry chemical extinguisher, what is the correct technique to operate it?","question_fil":"Kung magpasya ang isang kawani ng LGU na gamitin ang ABC dry chemical extinguisher, ano ang tamang pamamaraan upang paandarin ito?","explanation_en":"The proper technique for operating a fire extinguisher is PASS: Pull the pin, Aim at the base of the fire, Squeeze the handle, and Sweep side to side.","explanation_fil":"Ang tamang pamamaraan sa pagpapatakbo ng fire extinguisher ay PASS: Hilahin ang pin (Pull the pin), Itutok sa ilalim ng apoy (Aim at the base), Pisilin ang hawakan (Squeeze the handle), at Igulong mula sa gilid patungo sa gilid (Sweep side to side).","choice_a_en":"Aim at the flames, Sweep side to side, Pull the pin, Squeeze the handle (ASPS).","choice_a_fil":"Itutok sa apoy, Igulong mula sa gilid patungo sa gilid, Hilahin ang pin, Pisilin ang hawakan (ASPS).","choice_b_en":"Pull the pin, Aim at the base, Squeeze the handle, Sweep side to side (PASS).","choice_b_fil":"Hilahin ang pin, Itutok sa ilalim, Pisilin ang hawakan, Igulong mula sa gilid patungo sa gilid (PASS).","choice_c_en":"Squeeze the handle, Aim at the top, Pull the pin, Sweep up and down (SAPS).","choice_c_fil":"Pisilin ang hawakan, Itutok sa itaas, Hilahin ang pin, Igulong pataas at pababa (SAPS).","choice_d_en":"Push the lever, Activate the nozzle, Spray until empty, Stop (PASS is for CO2 only).","choice_d_fil":"Itulak ang lever, Aktibahin ang nozzle, I-spray hanggang maubos, Huminto (Ang PASS ay para lamang sa CO2).","is_manual":false,"status":"published"},{"number":13,"competency":"safety_awareness","correct_answer":"B","question_en":"After evacuating the building, where should all participants and staff gather?","question_fil":"Pagkatapos lumikas mula sa gusali, saan dapat magtipon ang lahat ng kalahok at kawani?","explanation_en":"A designated assembly point is crucial for accountability and ensuring everyone is safely away from the danger zone, facilitating headcounts.","explanation_fil":"Ang isang itinalagang lugar ng pagtitipon ay mahalaga para sa pananagutan at pagtiyak na ligtas ang lahat mula sa sona ng panganib, na nagpapadali sa pagbibilang ng tao.","choice_a_en":"Immediately outside the burning building to observe.","choice_a_fil":"Agad sa labas ng nasusunog na gusali upang obserbahan.","choice_b_en":"A pre-designated safe assembly point away from the building.","choice_b_fil":"Isang pre-designated na ligtas na lugar ng pagtitipon na malayo sa gusali.","choice_c_en":"The barangay hall nearby to wait for instructions.","choice_c_fil":"Ang barangay hall na malapit upang maghintay ng tagubilin.","choice_d_en":"Anywhere they feel safe, as long as it\'s outside.","choice_d_fil":"Kahit saan sila nakakaramdam ng kaligtasan, basta nasa labas.","is_manual":false,"status":"published"},{"number":14,"competency":"emergency_response","correct_answer":"B","question_en":"What is the crucial information to relay when calling the local fire department (BFP)?","question_fil":"Ano ang mahalagang impormasyon na dapat ipaabot kapag tumatawag sa lokal na kagawaran ng bumbero (BFP)?","explanation_en":"Providing clear, concise, and comprehensive information including the address, nature of the emergency, number of people, and hazards helps the BFP respond effectively.","explanation_fil":"Ang pagbibigay ng malinaw, tumpak, at komprehensibong impormasyon kabilang ang address, uri ng emerhensiya, bilang ng mga tao, at mga panganib ay nakakatulong sa BFP na tumugon nang epektibo.","choice_a_en":"Only the type of fire extinguisher available.","choice_a_fil":"Ang uri lamang ng fire extinguisher na magagamit.","choice_b_en":"Exact address, nature of the emergency, number of people involved, and any known hazards.","choice_b_fil":"Eksaktong address, uri ng emerhensiya, bilang ng mga taong sangkot, at anumang alam na panganib.","choice_c_en":"Only the number of people injured.","choice_c_fil":"Ang bilang lamang ng mga nasugatan.","choice_d_en":"The weather conditions at the time of the fire.","choice_d_fil":"Ang kalagayan ng panahon sa oras ng sunog.","is_manual":false,"status":"published"},{"number":15,"competency":"knowledge","correct_answer":"B","question_en":"What does it mean for a fire to be \'contained\' when considering using a fire extinguisher?","question_fil":"Ano ang ibig sabihin ng isang sunog na \'nakakulong\' (contained) kapag isinasaalang-alang ang paggamit ng fire extinguisher?","explanation_en":"A contained fire is one that is confined to a very small area and has not yet spread, making it potentially manageable with a portable extinguisher.","explanation_fil":"Ang nakakulong na sunog ay isa na limitado sa isang napakaliit na lugar at hindi pa kumalat, na ginagawa itong posibleng mapamahalaan gamit ang isang portable extinguisher.","choice_a_en":"The fire has spread to multiple rooms.","choice_a_fil":"Kumalat na ang sunog sa maraming silid.","choice_b_en":"The fire is limited to a small, isolated area, like a wastebasket or small appliance.","choice_b_fil":"Ang sunog ay limitado sa isang maliit, nakahiwalay na lugar, tulad ng basurahan o maliit na appliance.","choice_c_en":"The fire is producing a lot of smoke but no flames.","choice_c_fil":"Ang sunog ay naglalabas ng maraming usok ngunit walang apoy.","choice_d_en":"The fire is actively growing larger but still visible.","choice_d_fil":"Aktibong lumalaki ang sunog ngunit nakikita pa rin.","is_manual":false,"status":"published"},{"number":16,"competency":"decision_making","correct_answer":"C","question_en":"If after a brief attempt, the fire in the pantry does NOT immediately diminish, what should the LGU staff member do?","question_fil":"Kung pagkatapos ng maikling pagsubok, ang sunog sa pantry ay HINDI agad nabawasan, ano ang dapat gawin ng kawani ng LGU?","explanation_en":"If a fire doesn\'t respond quickly to an extinguisher, it\'s safer to abandon the attempt, ensure the door is closed (to contain smoke and fire), and prioritize complete evacuation. Personal safety always comes first.","explanation_fil":"Kung ang isang sunog ay hindi mabilis na tumugon sa isang extinguisher, mas ligtas na talikdan ang pagtatangka, tiyakin na nakasara ang pinto (upang makulong ang usok at apoy), at bigyang-prayoridad ang kumpletong paglikas. Laging nauuna ang personal na kaligtasan.","choice_a_en":"Continue fighting the fire until the extinguisher is empty.","choice_a_fil":"Patuloy na labanan ang apoy hanggang maubos ang extinguisher.","choice_b_en":"Get another extinguisher and try again.","choice_b_fil":"Kumuha ng isa pang extinguisher at subukang muli.","choice_c_en":"Immediately abandon the attempt, close the door (if safe), and prioritize full evacuation.","choice_c_fil":"Agad na talikdan ang pagtatangka, isara ang pinto (kung ligtas), at bigyang-prayoridad ang kumpletong paglikas.","choice_d_en":"Wait for the fire to reduce in size naturally.","choice_d_fil":"Hintayin na natural na lumiit ang apoy.","is_manual":false,"status":"published"},{"number":17,"competency":"safety_awareness","correct_answer":"C","question_en":"During the evacuation, if a participant\'s clothing catches fire, what is the most appropriate instruction to give them?","question_fil":"Sa panahon ng paglikas, kung nasunog ang damit ng isang kalahok, ano ang pinakaangkop na tagubilin na ibibigay sa kanila?","explanation_en":"\'Stop, Drop, and Roll\' is the internationally recognized and most effective method to extinguish flames on a person\'s clothing.","explanation_fil":"Ang \'Huminto, Dumapa, at Gumulong\' (Stop, Drop, and Roll) ay ang pandaigdigang kinikilala at pinakaepektibong paraan upang patayin ang apoy sa damit ng isang tao.","choice_a_en":"Run towards the exit as fast as possible.","choice_a_fil":"Tumakbo patungo sa labasan nang mabilis hangga\'t maaari.","choice_b_en":"Pat the fire out with their hands.","choice_b_fil":"Palayain ang apoy gamit ang kanilang mga kamay.","choice_c_en":"Stop, Drop, and Roll.","choice_c_fil":"Huminto, Dumapa, at Gumulong (Stop, Drop, and Roll).","choice_d_en":"Remove the burning clothing immediately.","choice_d_fil":"Tanggalin agad ang nasusunog na damit.","is_manual":false,"status":"published"},{"number":18,"competency":"emergency_response","correct_answer":"B","question_en":"Upon arrival at the assembly point, what is the primary responsibility of the LGU staff member in charge?","question_fil":"Pagdating sa assembly point, ano ang pangunahing responsibilidad ng kawani ng LGU na namamahala?","explanation_en":"Accountability is critical post-evacuation. A headcount helps determine if everyone safely evacuated and alerts emergency responders if anyone is still inside.","explanation_fil":"Ang pananagutan ay kritikal pagkatapos ng paglikas. Nakakatulong ang headcount upang matukoy kung ligtas na nakalikas ang lahat at alertuhin ang mga emergency responder kung mayroon pa ring nasa loob.","choice_a_en":"Contact relatives of the participants.","choice_a_fil":"Makipag-ugnayan sa mga kamag-anak ng mga kalahok.","choice_b_en":"Perform a headcount and report any missing individuals to the BFP.","choice_b_fil":"Magsagawa ng headcount at iulat ang sinumang nawawalang indibidwal sa BFP.","choice_c_en":"Go back inside the building to check for missing items.","choice_c_fil":"Bumalik sa loob ng gusali upang tingnan kung may nawawalang gamit.","choice_d_en":"Debrief the participants about the fire causes.","choice_d_fil":"I-debrief ang mga kalahok tungkol sa mga sanhi ng sunog.","is_manual":false,"status":"published"},{"number":19,"competency":"knowledge","correct_answer":"D","question_en":"Which of the following is NOT a common cause of fire incidents according to fire safety principles?","question_fil":"Alin sa mga sumusunod ang HINDI karaniwang sanhi ng mga insidente ng sunog ayon sa mga prinsipyo ng kaligtasan sa sunog?","explanation_en":"Well-maintained fire extinguishers are a fire *safety device*, not a cause of fire. The other options are recognized common causes.","explanation_fil":"Ang maayos na inaalagaan na mga fire extinguisher ay isang kagamitan para sa *kaligtasan sa sunog*, hindi sanhi ng sunog. Ang iba pang mga opsyon ay kinikilalang karaniwang sanhi.","choice_a_en":"Electrical overloading.","choice_a_fil":"Sobrang karga ng kuryente.","choice_b_en":"Unattended cooking.","choice_b_fil":"Hindi binabantayang pagluluto.","choice_c_en":"Improper storage of flammable materials.","choice_c_fil":"Hindi wastong pagtabi ng mga madaling magliyab na materyales.","choice_d_en":"Well-maintained and regularly inspected fire extinguishers.","choice_d_fil":"Maayos na inaalagaan at regular na iniinspeksyon na mga fire extinguisher.","is_manual":false,"status":"published"},{"number":20,"competency":"decision_making","correct_answer":"B","question_en":"An LGU staff member observes that the smoke from the pantry is now thick and dark, and visibility is severely reduced. What is the most appropriate decision regarding any attempt to suppress the fire?","question_fil":"Napansin ng isang kawani ng LGU na ang usok mula sa pantry ay makapal na at madilim, at lubhang nabawasan ang visibility. Ano ang pinakaangkop na desisyon tungkol sa anumang pagtatangka na apulahin ang apoy?","explanation_en":"Thick, dark smoke and reduced visibility indicate a rapidly escalating and dangerous fire. At this point, personal safety and ensuring everyone\'s evacuation take absolute precedence over any attempt at fire suppression by untrained personnel.","explanation_fil":"Ang makapal, madilim na usok at nabawasang visibility ay nagpapahiwatig ng mabilis na lumalala at mapanganib na sunog. Sa puntong ito, ang personal na kaligtasan at pagtiyak sa paglikas ng lahat ay ganap na mas mahalaga kaysa sa anumang pagtatangka na apulahin ang sunog ng mga hindi sinanay na tauhan.","choice_a_en":"Proceed with caution, as long as an extinguisher is still nearby.","choice_a_fil":"Magpatuloy nang maingat, basta\'t malapit pa rin ang extinguisher.","choice_b_en":"Abandon any fire suppression efforts immediately and focus solely on safe evacuation.","choice_b_fil":"Agad na talikdan ang anumang pagtatangka sa pagpatay ng sunog at tumutok lamang sa ligtas na paglikas.","choice_c_en":"Attempt to ventilate the area before using the extinguisher.","choice_c_fil":"Subukang i-ventilate ang lugar bago gamitin ang extinguisher.","choice_d_en":"Wait for the smoke to clear slightly before approaching.","choice_d_fil":"Hintayin na bahagyang luminaw ang usok bago lumapit.","is_manual":false,"status":"published"},{"question_en":"New scenario question","choice_a_en":"Option A","choice_b_en":"Option B","choice_c_en":"Option C","choice_d_en":"Option D","correct_answer":"A","explanation_en":"","competency":"knowledge","question_fil":"","explanation_fil":"","choice_a_fil":"","choice_b_fil":"","choice_c_fil":"","choice_d_fil":"","number":21,"is_manual":true,"status":"published"}]', '2026-07-10 03:34:54', '2026-07-10 03:34:54', 3, '2026-06-27 16:38:48', '2026-07-16 11:48:10'),
