	(148, 3, 'Reymon', 'LGU_ADMIN', 'Published simulation event', 'Simulation Events', 'success', '127.0.0.1', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/149.0.0.0 Safari/537.36', 'http://127.0.0.1:8000/admin/simulation-events/3/publish', 'Title: How to use fire extinguisher', NULL, '{"id":3,"title":"How to use fire extinguisher","disaster_type":"Fire Safety","description":"Participants are community members attending a fire safety drill. The drill simulates a small, contained fire incident (e.g., a trash bin fire or a small liquid spill fire) in a designated open area. The objective is for participants to correctly identify the fire type, select the appropriate extinguisher, and apply the \'PASS\' method to safely put out the fire.","event_category":"Drill","status":"draft","event_date":"2026-07-12T16:00:00.000000Z","start_time":"08:00:00","end_time":"12:00:00","is_recurring":false,"recurrence_pattern":null,"location":"City Hall","venue":"City Hall","building":null,"room_zone":null,"location_notes":null,"accessibility_notes":null,"exits":null,"hazard_zones":null,"assembly_points":null,"is_high_risk_location":false,"scenario_id":null,"training_module_id":8,"campaign_request_id":8,"simulation_exercise_template_id":2,"barangay_profile_id":null,"scenario_is_required":true,"facilitators":null,"assigned_trainer_id":null,"allowed_participant_types":null,"target_audience":"Barangay Officials, Community Volunteers","max_participants":22,"registration_deadline":"2026-07-07T14:11:18.000000Z","self_registration_enabled":true,"approval_required":true,"qr_code_enabled":false,"attendance_code":null,"reserved_resources":null,"safety_guidelines":"Always prioritize personal safety. Do not attempt to fight fires that are too large, spreading rapidly, or if you lack a clear escape route. Ensure proper PPE (gloves, safety glasses) if provided. Follow all instructions from the Safety Officer and Trainers. Report any discomfort or incident immediately.","hazard_warnings":null,"required_ppe":null,"event_phases":[{"order":1,"title":"Registration, Orientation & Safety Briefing","duration_minutes":20,"description":"Participants register, receive an overview of the exercise objectives, schedule, and critical safety protocols, including emergency exits and first aid points. Emphasize the \'Stop, Drop, and Roll\' principle if clothing catches fire and the importance of not attempting to fight large fires."},{"order":2,"title":"Introduction to Fire Safety and Extinguishers","duration_minutes":30,"description":"A theoretical session covering the basics of fire (fire triangle), different classes of fire (A, B, C, D, K), types of fire extinguishers, and the \'PASS\' method (Pull, Aim, Squeeze, Sweep) for effective operation. Discussion on when to fight a fire versus when to evacuate."},{"order":3,"title":"Live Demonstration of Fire Extinguisher Use","duration_minutes":25,"description":"The Lead Trainer demonstrates the proper handling and operation of a fire extinguisher on a controlled, simulated fire (e.g., fire pan). Emphasis on safety distance, aiming at the base of the fire, and sweeping motion."},{"order":4,"title":"Hands-on Practice: Dry Run (PASS Method)","duration_minutes":40,"description":"Participants practice the \'PASS\' method using discharged or training fire extinguishers without live fire. This activity focuses on muscle memory for pulling the pin, aiming, squeezing the handle, and sweeping motion. Trainers provide immediate feedback."},{"order":5,"title":"Simulated Fire Extinguishment Drill","duration_minutes":40,"description":"Under strict supervision, participants take turns extinguishing a small, controlled fire (e.g., in a fire pan or designated burn area) using a live fire extinguisher. This activity tests their practical application of the \'PASS\' method in a realistic scenario."},{"order":6,"title":"Debriefing, Q&A, and Feedback","duration_minutes":20,"description":"A facilitated discussion reviewing the exercise, addressing participant questions, clarifying misconceptions, and gathering feedback. Trainers provide constructive criticism and reinforce key learning points. Certificates of participation may be distributed."}],"inject_triggers":null,"facilitator_instructions":"Exercise Template: How to use fire extinguisher\\n\\nRecommended Personnel: Lead Trainer (1), Assistant Trainer (2), Safety Officer (1), Marshal (2), Medical Team (2), Evaluator (2), Communication Officer (1)\\n\\nRecommended Equipment: Fire Extinguisher x2, Fire Extinguisher x5, Fire Extinguisher x8, First Aid Kit x1, Emergency Light x2\\n\\nActivities:\\n1. Registration, Orientation & Safety Briefing (20 min)\\n2. Introduction to Fire Safety and Extinguishers (30 min)\\n3. Live Demonstration of Fire Extinguisher Use (25 min)\\n4. Hands-on Practice: Dry Run (PASS Method) (40 min)\\n5. Simulated Fire Extinguishment Drill (40 min)\\n6. Debriefing, Q&A, and Feedback (20 min)\\n\\nEvaluation Objectives:\\n\\u2022 At least 90% of participants can correctly identify the four main classes of fire and their corresponding extinguisher types during post-activity questioning.\\n\\u2022 At least 85% of participants can execute the \'PASS\' method correctly during the dry run, demonstrating proper sequence and technique.\\n\\u2022 At least 80% of participants can successfully extinguish a controlled simulated fire using a fire extinguisher, applying the \'PASS\' method effectively and safely.\\n\\u2022 All participants adhere to safety instructions and maintain appropriate distance from the fire during the live fire drill, as observed by the Safety Officer and Evaluators.\\n\\u2022 At least 75% of participants express increased confidence in their ability to use a fire extinguisher in an emergency, as indicated by post-exercise feedback forms.","email_notifications_enabled":true,"sms_notifications_enabled":false,"notification_schedule":null,"created_by":3,"updated_by":3,"published_at":null,"completed_at":null,"created_at":"2026-07-13T05:06:51.000000Z","updated_at":"2026-07-13T05:06:51.000000Z","actual_start_time":null,"started_by":null,"readiness_confirmations":null,"execution_progress":null,"timeline_entries":[{"time":"08:05","label":"Registration, Orientation & Safety Briefing","description":"Participants register, receive an overview of the exercise objectives, schedule, and critical safety protocols, including emergency exits and first aid points. Emphasize the \'Stop, Drop, and Roll\' principle if clothing catches fire and the importance of not attempting to fight large fires."},{"time":"08:25","label":"Introduction to Fire Safety and Extinguishers","description":"A theoretical session covering the basics of fire (fire triangle), different classes of fire (A, B, C, D, K), types of fire extinguishers, and the \'PASS\' method (Pull, Aim, Squeeze, Sweep) for effective operation. Discussion on when to fight a fire versus when to evacuate."},{"time":"08:55","label":"Live Demonstration of Fire Extinguisher Use","description":"The Lead Trainer demonstrates the proper handling and operation of a fire extinguisher on a controlled, simulated fire (e.g., fire pan). Emphasis on safety distance, aiming at the base of the fire, and sweeping motion."},{"time":"09:20","label":"Hands-on Practice: Dry Run (PASS Method)","description":"Participants practice the \'PASS\' method using discharged or training fire extinguishers without live fire. This activity focuses on muscle memory for pulling the pin, aiming, squeezing the handle, and sweeping motion. Trainers provide immediate feedback."},{"time":"10:00","label":"Simulated Fire Extinguishment Drill","description":"Under strict supervision, participants take turns extinguishing a small, controlled fire (e.g., in a fire pan or designated burn area) using a live fire extinguisher. This activity tests their practical application of the \'PASS\' method in a realistic scenario."},{"time":"10:40","label":"Debriefing, Q&A, and Feedback","description":"A facilitated discussion reviewing the exercise, addressing participant questions, clarifying misconceptions, and gathering feedback. Trainers provide constructive criticism and reinforce key learning points. Certificates of participation may be distributed."}],"post_evaluation":null}', '{"id":3,"title":"How to use fire extinguisher","disaster_type":"Fire Safety","description":"Participants are community members attending a fire safety drill. The drill simulates a small, contained fire incident (e.g., a trash bin fire or a small liquid spill fire) in a designated open area. The objective is for participants to correctly identify the fire type, select the appropriate extinguisher, and apply the \'PASS\' method to safely put out the fire.","event_category":"Drill","status":"published","event_date":"2026-07-12T16:00:00.000000Z","start_time":"08:00:00","end_time":"12:00:00","is_recurring":false,"recurrence_pattern":null,"location":"City Hall","venue":"City Hall","building":null,"room_zone":null,"location_notes":null,"accessibility_notes":null,"exits":null,"hazard_zones":null,"assembly_points":null,"is_high_risk_location":false,"scenario_id":null,"training_module_id":8,"campaign_request_id":8,"simulation_exercise_template_id":2,"barangay_profile_id":null,"scenario_is_required":true,"facilitators":null,"assigned_trainer_id":null,"allowed_participant_types":null,"target_audience":"Barangay Officials, Community Volunteers","max_participants":22,"registration_deadline":"2026-07-07T14:11:18.000000Z","self_registration_enabled":true,"approval_required":true,"qr_code_enabled":false,"attendance_code":null,"reserved_resources":null,"safety_guidelines":"Always prioritize personal safety. Do not attempt to fight fires that are too large, spreading rapidly, or if you lack a clear escape route. Ensure proper PPE (gloves, safety glasses) if provided. Follow all instructions from the Safety Officer and Trainers. Report any discomfort or incident immediately.",