	(2, 3, 1, 'archived', '[{"number":1,"competency":"knowledge","correct_answer":"B","question_en":"According to the lesson, what is fire primarily defined as?","question_fil":"Ayon sa aralin, ano ang pangunahing kahulugan ng sunog?","explanation_en":"The lesson states: \'Fire is a chemical reaction called combustion, which occurs when three essential elements combine: Heat Fuel Oxygen\'.","explanation_fil":"Nakasaad sa aralin: \'Ang sunog ay isang kemikal na reaksyon na tinatawag na kombustyon, na nangyayari kapag nagsama-sama ang tatlong mahahalagang elemento: Init, Gatong, Oxygen\'.","choice_a_en":"A physical reaction producing light and heat","choice_a_fil":"Isang pisikal na reaksyon na gumagawa ng liwanag at init","choice_b_en":"A chemical reaction called combustion","choice_b_fil":"Isang kemikal na reaksyon na tinatawag na kombustyon","choice_c_en":"A rapid expansion of hot gases","choice_c_fil":"Isang mabilis na paglawak ng mainit na gas","choice_d_en":"A phenomenon of rapid material decomposition","choice_d_fil":"Isang phenomenon ng mabilis na pagkabulok ng materyal"},{"number":2,"competency":"knowledge","correct_answer":"B","question_en":"Which three essential elements combine to form the Fire Triangle?","question_fil":"Aling tatlong mahahalagang elemento ang nagsasama-sama upang mabuo ang Fire Triangle?","explanation_en":"The lesson identifies the three elements forming the Fire Triangle as \'Heat Fuel Oxygen\'.","explanation_fil":"Tinukoy ng aralin ang tatlong elementong bumubuo sa Fire Triangle bilang \'Init, Gatong, Oxygen\'.","choice_a_en":"Light, Fuel, Oxygen","choice_a_fil":"Liwanag, Gatong, Oxygen","choice_b_en":"Heat, Fuel, Oxygen","choice_b_fil":"Init, Gatong, Oxygen","choice_c_en":"Smoke, Heat, Oxygen","choice_c_fil":"Usok, Init, Oxygen","choice_d_en":"Fuel, Carbon Dioxide, Heat","choice_d_fil":"Gatong, Carbon Dioxide, Init"},{"number":3,"competency":"knowledge","correct_answer":"C","question_en":"What will happen if any one of the three elements of the Fire Triangle is removed?","question_fil":"Ano ang mangyayari kung aalisin ang alinman sa tatlong elemento ng Fire Triangle?","explanation_en":"The lesson states: \'If any one of these elements is removed, the fire will be extinguished\'.","explanation_fil":"Nakasaad sa aralin: \'Kung aalisin ang alinman sa mga elementong ito, ang sunog ay mamamatay\'.","choice_a_en":"The fire will intensify","choice_a_fil":"Ang sunog ay titindi","choice_b_en":"The fire will spread","choice_b_fil":"Ang sunog ay kakalat","choice_c_en":"The fire will be extinguished","choice_c_fil":"Ang sunog ay mamamatay","choice_d_en":"The fire will change color","choice_d_fil":"Magbabago ang kulay ng apoy"},{"number":4,"competency":"knowledge","correct_answer":"B","question_en":"In the context of the Fire Triangle, what is the primary role of Heat?","question_fil":"Sa konteksto ng Fire Triangle, ano ang pangunahing papel ng Init?","explanation_en":"The lesson explains: \'Heat provides the energy needed to ignite combustible materials\'.","explanation_fil":"Ipinaliliwanag ng aralin: \'Nagbibigay ang Init ng enerhiya na kailangan upang pagliyabin ang mga nasusunog na materyales\'.","choice_a_en":"To act as fuel","choice_a_fil":"Para magsilbing gatong","choice_b_en":"To ignite combustible materials","choice_b_fil":"Upang pagliyabin ang mga nasusunog na materyales","choice_c_en":"To reduce oxygen supply","choice_c_fil":"Upang bawasan ang suplay ng oxygen","choice_d_en":"To increase visibility during a fire","choice_d_fil":"Upang mapataas ang kakayahang makakita sa panahon ng sunog"},{"number":5,"competency":"knowledge","correct_answer":"C","question_en":"Which of the following is an example of \'Fuel\' as defined in the Fire Triangle?","question_fil":"Alin sa mga sumusunod ang halimbawa ng \'Gatong\' tulad ng tinukoy sa Fire Triangle?","explanation_en":"The lesson lists \'Gasoline\' as an example of fuel, stating: \'Fuel is any combustible material that can burn. Examples: ... Gasoline\'.","explanation_fil":"Nakasaad sa aralin na ang \'Gasolina\' ay halimbawa ng gatong, at sinasabing: \'Ang gatong ay anumang nasusunog na materyal na maaaring magliyab. Mga Halimbawa: ... Gasolina\'.","choice_a_en":"Electrical sparks","choice_a_fil":"Kislap ng kuryente","choice_b_en":"Open flames","choice_b_fil":"Bukas na apoy","choice_c_en":"Gasoline","choice_c_fil":"Gasolina","choice_d_en":"Oxygen","choice_d_fil":"Oxygen"},{"number":6,"competency":"knowledge","correct_answer":"C","question_en":"What is the role of Oxygen in the Fire Triangle?","question_fil":"Ano ang papel ng Oxygen sa Fire Triangle?","explanation_en":"The lesson states: \'Oxygen in the air supports combustion\'.","explanation_fil":"Nakasaad sa aralin: \'Ang Oxygen sa hangin ay sumusuporta sa kombustyon\'.","choice_a_en":"To cool down the fire","choice_a_fil":"Upang palamigin ang apoy","choice_b_en":"To remove fuel from the fire","choice_b_fil":"Upang alisin ang gatong mula sa apoy","choice_c_en":"To support combustion","choice_c_fil":"Upang suportahan ang kombustyon","choice_d_en":"To provide a barrier against fire spread","choice_d_fil":"Upang magbigay ng harang laban sa pagkalat ng apoy"},{"number":7,"competency":"emergency_response","correct_answer":"C","question_en":"Removing oxygen, such as by covering a fire with a fire blanket, can extinguish what type of fires?","question_fil":"Ang pag-alis ng oxygen, tulad ng pagtakip sa sunog gamit ang fire blanket, ay makasusugpo ng anong uri ng sunog?","explanation_en":"The lesson mentions: \'Removing oxygen (such as covering a fire with a fire blanket) can extinguish certain types of fires\'.","explanation_fil":"Binanggit sa aralin: \'Ang pag-alis ng oxygen (tulad ng pagtakip sa sunog gamit ang fire blanket) ay makasusugpo ng ilang uri ng sunog\'.","choice_a_en":"Only electrical fires","choice_a_fil":"Mga sunog na elektrikal lamang","choice_b_en":"Only liquid fires","choice_b_fil":"Mga sunog na likido lamang","choice_c_en":"Certain types of fires","choice_c_fil":"Ilang uri ng sunog","choice_d_en":"All types of fires","choice_d_fil":"Lahat ng uri ng sunog"},{"number":8,"competency":"knowledge","correct_answer":"B","question_en":"Class A Fires involve which type of materials?","question_fil":"Anong uri ng materyales ang nasasangkot sa Class A Fires?","explanation_en":"The lesson defines: \'Class A Fires Ordinary combustible materials\'.","explanation_fil":"Ang aralin ay nagbibigay-kahulugan: \'Class A Fires: Mga ordinaryong materyales na nasusunog\'.","choice_a_en":"Flammable liquids","choice_a_fil":"Mga likidong madaling magliyab","choice_b_en":"Ordinary combustible materials","choice_b_fil":"Mga ordinaryong materyales na nasusunog","choice_c_en":"Energized electrical equipment","choice_c_fil":"Mga kagamitang elektrikal na may kuryente","choice_d_en":"Reactive metals","choice_d_fil":"Mga reaktibong metal"},{"number":9,"competency":"knowledge","correct_answer":"C","question_en":"Which of the following is an example of a material involved in a Class A Fire?","question_fil":"Alin sa mga sumusunod ang halimbawa ng materyal na nasasangkot sa Class A Fire?","explanation_en":"The lesson lists \'Wood\' as an example of Class A fires: \'Examples: Wood Paper Cloth Rubber Plastic\'.","explanation_fil":"Nakasaad sa aralin ang \'Kahoy\' bilang halimbawa ng Class A fires: \'Mga Halimbawa: Kahoy, Papel, Tela, Goma, Plastik\'.","choice_a_en":"Gasoline","choice_a_fil":"Gasolina","choice_b_en":"Paint","choice_b_fil":"Pintura","choice_c_en":"Wood","choice_c_fil":"Kahoy","choice_d_en":"Electrical panel","choice_d_fil":"Electrical panel"},{"number":10,"competency":"knowledge","correct_answer":"C","question_en":"What materials are involved in Class B Fires?","question_fil":"Anong materyales ang nasasangkot sa Class B Fires?","explanation_en":"The lesson specifies: \'Class B Fires Flammable liquids\'.","explanation_fil":"Tinukoy ng aralin: \'Class B Fires: Mga likidong madaling magliyab\'.","choice_a_en":"Ordinary combustibles","choice_a_fil":"Mga ordinaryong nasusunog","choice_b_en":"Flammable gases","choice_b_fil":"Mga gas na madaling magliyab","choice_c_en":"Flammable liquids","choice_c_fil":"Mga likidong madaling magliyab","choice_d_en":"Cooking oils","choice_d_fil":"Mga mantika sa pagluluto"},{"number":11,"competency":"knowledge","correct_answer":"B","question_en":"An alcohol fire would be classified under which fire class?","question_fil":"Sa anong klase ng sunog maiuuri ang sunog na dulot ng alkohol?","explanation_en":"The lesson includes \'Alcohol\' as an example of a Class B fire: \'Examples: Gasoline Diesel Paint Oil Alcohol\'.","explanation_fil":"Kasama sa aralin ang \'Alcohol\' bilang halimbawa ng Class B fire: \'Mga Halimbawa: Gasolina, Diesel, Pintura, Langis, Alkohol\'.","choice_a_en":"Class A","choice_a_fil":"Class A","choice_b_en":"Class B","choice_b_fil":"Class B","choice_c_en":"Class C","choice_c_fil":"Class C","choice_d_en":"Class D","choice_d_fil":"Class D"},{"number":12,"competency":"knowledge","correct_answer":"C","question_en":"Class C Fires involve what kind of equipment?","question_fil":"Anong uri ng kagamitan ang nasasangkot sa Class C Fires?","explanation_en":"The lesson defines: \'Class C Fires Electrical fires involving energized electrical equipment\'.","explanation_fil":"Ang aralin ay nagbibigay-kahulugan: \'Class C Fires: Mga sunog na elektrikal na nasasangkot sa mga kagamitang elektrikal na may kuryente\'.","choice_a_en":"Ordinary combustible materials","choice_a_fil":"Mga ordinaryong materyales na nasusunog","choice_b_en":"Flammable liquids","choice_b_fil":"Mga likidong madaling magliyab","choice_c_en":"Energized electrical equipment","choice_c_fil":"Mga kagamitang elektrikal na may kuryente","choice_d_en":"Combustible metals","choice_d_fil":"Mga metal na nasusunog"},{"number":13,"competency":"knowledge","correct_answer":"C","question_en":"Which of the following is an example of a potential Class C fire hazard?","question_fil":"Alin sa mga sumusunod ang halimbawa ng posibleng panganib ng Class C fire?","explanation_en":"The lesson lists \'Overloaded electrical outlets\' as a common fire hazard, which directly relates to energized electrical equipment (Class C fires).","explanation_fil":"Nakasaad sa aralin ang \'Mga labis na kargadong saksakan ng kuryente\' bilang isang karaniwang panganib ng sunog, na direktang nauugnay sa mga kagamitang elektrikal na may kuryente (Class C fires).","choice_a_en":"Burning paper","choice_a_fil":"Nasusunog na papel","choice_b_en":"Leaking diesel","choice_b_fil":"Tumutulong diesel","choice_c_en":"An overloaded electrical outlet","choice_c_fil":"Isang labis na kargadong saksakan ng kuryente","choice_d_en":"A stack of rubber tires","choice_d_fil":"Tumpok ng gulong na goma"},{"number":14,"competency":"safety_awareness","correct_answer":"B","question_en":"Which of the following is identified as a common fire hazard in the lesson?","question_fil":"Alin sa mga sumusunod ang tinukoy bilang karaniwang panganib ng sunog sa aralin?","explanation_en":"The lesson explicitly lists \'Unattended cooking\' as a common fire hazard.","explanation_fil":"Malinaw na nakasaad sa aralin ang \'Hindi binabantayang pagluluto\' bilang isang karaniwang panganib ng sunog.","choice_a_en":"Properly stored flammable materials","choice_a_fil":"Wastong nakaimbak na mga materyales na madaling magliyab","choice_b_en":"Unattended cooking","choice_b_fil":"Hindi binabantayang pagluluto","choice_c_en":"Adequate ventilation","choice_c_fil":"Sapat na bentilasyon","choice_d_en":"Covered electrical outlets","choice_d_fil":"Mga saksakan ng kuryente na may takip"},{"number":15,"competency":"knowledge","correct_answer":"C","question_en":"According to the lesson, what is the primary cause of many fire-related deaths?","question_fil":"Ayon sa aralin, ano ang pangunahing sanhi ng maraming pagkamatay na may kaugnayan sa sunog?","explanation_en":"The lesson states: \'Many fire-related deaths are caused by smoke inhalation rather than burns\'.","explanation_fil":"Nakasaad sa aralin: \'Maraming pagkamatay na may kaugnayan sa sunog ang sanhi ng pagsinghot ng usok sa halip na pagkasunog\'.","choice_a_en":"Burns from flames","choice_a_fil":"Pagkasunog mula sa apoy","choice_b_en":"Structural collapse","choice_b_fil":"Pagguho ng istruktura","choice_c_en":"Smoke inhalation","choice_c_fil":"Pagsinghot ng usok","choice_d_en":"Explosions","choice_d_fil":"Mga pagsabog"},{"number":16,"competency":"knowledge","correct_answer":"C","question_en":"Which of the following is a danger caused by smoke containing harmful gases?","question_fil":"Alin sa mga sumusunod ang panganib na dulot ng usok na naglalaman ng nakakapinsalang gas?","explanation_en":"The lesson lists: \'Smoke contains harmful gases that can: ... Result in suffocation\'.","explanation_fil":"Nakasaad sa aralin: \'Naglalaman ang usok ng nakakapinsalang gas na maaaring: ... Magdulot ng pagkasakal\'.","choice_a_en":"Increased visibility","choice_a_fil":"Pagtaas ng kakayahang makakita","choice_b_en":"Enhanced breathing","choice_b_fil":"Pagpapabuti ng paghinga","choice_c_en":"Suffocation","choice_c_fil":"Pagkasakal","choice_d_en":"Accelerated healing","choice_d_fil":"Pinabilis na paggaling"},{"number":17,"competency":"emergency_response","correct_answer":"C","question_en":"During evacuation from a fire, what specific action is recommended to avoid smoke?","question_fil":"Sa panahon ng paglikas mula sa sunog, anong tiyak na aksyon ang inirerekomenda upang maiwasan ang usok?","explanation_en":"The lesson advises: \'During evacuation: Stay low to avoid smoke\'.","explanation_fil":"Pinapayuhan ng aralin: \'Sa panahon ng paglikas: Manatili sa mababang posisyon upang maiwasan ang usok\'.","choice_a_en":"Stand tall to see better","choice_a_fil":"Tumayo nang tuwid upang mas makakita","choice_b_en":"Run quickly through smoke","choice_b_fil":"Mabilis na tumakbo sa usok","choice_c_en":"Stay low to avoid smoke","choice_c_fil":"Manatili sa mababang posisyon upang maiwasan ang usok","choi