	(4, 9, 'Introduction', 'text', 'Learn how fires start, spread, and behave in residential and community settings.', NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, '2026-07-09 04:19:46', '2026-07-09 04:19:46'),
