	(1, 'Night-time Barangay Fire', 'Fire breaks out in a residential block during the night shift.', 'Residential Zone 3', 'Fire', 'Intermediate', 'Barangay DRRM team, fire volunteers, community leaders', 'Emphasize safe distance from fire perimeter; use proper PPE.', '22:30', '10:30 PM', 'Multiple households are affected by a rapidly spreading fire.', 'High', 'Dry and windy', 'Urban barangay', 0, 2, 1, 'Three houses partially damaged.', 'Intermittent mobile signal; radios available.', 'Coordinate fire response and evacuation at barangay level.', 'Incident command, communication, evacuation management.', '[]', 5, 1, 'published', 1, 1, '2026-07-09 04:19:46', '2026-07-16 05:51:18'),
	(2, 'Monsoon Flooding along Creekside', 'Continuous heavy rain causes flooding in low-lying areas.', 'Creekside Barangay', 'Flood', 'Intermediate', 'Barangay DRRM team, health workers, community volunteers', 'Watch for open manholes and electrical hazards.', '15:00', '3:00 PM', 'Water levels continue to rise; some houses are partially submerged.', 'Moderate', 'Heavy monsoon rains', 'Flood-prone urban barangay', 0, 0, 0, 'Minor damage to roads and flood barriers.', 'Stable mobile and radio communication.', 'Coordinate early evacuation and relief site operations.', 'Early warning, evacuation logistics, relief planning.', '[]', 5, 0, 'published', 1, 1, '2026-07-09 04:19:46', '2026-07-16 05:51:18');
