REPLACE INTO `simulation_events` (`id`, `title`, `disaster_type`, `description`, `event_category`, `status`, `event_date`, `start_time`, `end_time`, `is_recurring`, `recurrence_pattern`, `location`, `venue`, `building`, `room_zone`, `location_notes`, `accessibility_notes`, `exits`, `hazard_zones`, `assembly_points`, `is_high_risk_location`, `scenario_id`, `training_module_id`, `campaign_request_id`, `simulation_exercise_template_id`, `barangay_profile_id`, `scenario_is_required`, `facilitators`, `assigned_trainer_id`, `allowed_participant_types`, `target_audience`, `max_participants`, `registration_deadline`, `self_registration_enabled`, `approval_required`, `qr_code_enabled`, `attendance_code`, `reserved_resources`, `safety_guidelines`, `hazard_warnings`, `required_ppe`, `event_phases`, `inject_triggers`, `facilitator_instructions`, `email_notifications_enabled`, `sms_notifications_enabled`, `notification_schedule`, `created_by`, `updated_by`, `published_at`, `completed_at`, `created_at`, `updated_at`, `actual_start_time`, `started_by`, `readiness_confirmations`, `execution_progress`, `timeline_entries`, `post_evaluation`) VALUES
	(1, 'Quarterly Fire Drill - Barangay Hall', 'Fire', 'Simulation of a fire incident in the barangay hall with full evacuation drill.', 'Drill', 'ended', '2026-07-04', '09:00:00', '11:00:00', 0, NULL, 'Barangay Hall', NULL, 'Main Building', 'Ground Floor', 'Assembly point at covered court.', 'Wheelchair access available at side entrance.', 'Front main exit, side exit near records room.', 'Records room, pantry area.', 'Covered court across the street.', 1, NULL, NULL, NULL, NULL, 4, 1, '["JB"]', NULL, '["LGU_ADMIN","LGU_TRAINER","PARTICIPANT"]', NULL, 80, NULL, 1, 0, 1, 'FIREDRILL', '[]', 'Wear closed shoes and follow marshal instructions.', 'Simulated smoke may affect people with respiratory conditions.', 'Closed shoes; optional face mask.', '["Briefing","Alarm","Evacuation","Debriefing"]', '[]', 'Ensure all zones are checked and accounted for during debrief.', 1, 0, '[]', 1, 3, NULL, NULL, '2026-06-27 12:04:21', '2026-07-09 04:20:07', NULL, NULL, NULL, NULL, NULL, NULL),
	(2, 'Completed Earthquake Drill - Municipal Hall', 'Earthquake', 'Previously conducted earthquake drill to showcase completed event state.', 'Drill', 'completed', '2026-06-17', '10:00:00', '12:00:00', 0, NULL, 'Municipal Hall', NULL, 'Main Building', 'Second Floor', 'Assembly point at open parking lot.', 'Elevator and ramp available.', 'Main stairwell, emergency back exit.', 'Glass-front offices, storage areas.', 'Open parking lot behind the building.', 1, 1, NULL, NULL, NULL, 6, 1, '["JB"]', NULL, '["LGU_ADMIN","LGU_TRAINER","PARTICIPANT"]', NULL, 120, NULL, 1, 0, 1, 'EQUAKE2026', '[]', 'Follow drop-cover-hold protocol and move calmly to assembly area.', 'Falling objects during simulated shaking.', 'Closed shoes; optional hard hat for facilitators.', '["Briefing","Shaking Simulation","Evacuation","Headcount","Debriefing"]', '[]', 'Emphasize calm evacuation and account for all staff.', 1, 0, '[]', 1, 1, NULL, NULL, '2026-06-27 12:04:21', '2026-07-09 04:19:46', NULL, NULL, NULL, NULL, NULL, NULL),
	(3, 'How to use fire extinguisher', 'Fire Safety', 'Participants are community members attending a fire safety drill. The drill simulates a small, contained fire incident (e.g., a trash bin fire or a small liquid spill fire) in a designated open area. The objective is for participants to correctly identify the fire type, select the appropriate extinguisher, and apply the \'PASS\' method to safely put out the fire.', 'Drill', 'ended', '2026-07-13', '08:00:00', '12:00:00', 0, NULL, 'City Hall', 'City Hall', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, 8, 8, 2, NULL, 1, NULL, NULL, NULL, 'Barangay Officials, Community Volunteers', 22, '2026-07-07 22:11:18', 1, 1, 0, NULL, NULL, 'Always prioritize personal safety. Do not attempt to fight fires that are too large, spreading rapidly, or if you lack a clear escape route. Ensure proper PPE (gloves, safety glasses) if provided. Follow all instructions from the Safety Officer and Trainers. Report any discomfort or incident immediately.', NULL, NULL, '[{"order":1,"title":"Registration, Orientation & Safety Briefing","duration_minutes":20,"description":"Participants register, receive an overview of the exercise objectives, schedule, and critical safety protocols, including emergency exits and first aid points. Emphasize the \'Stop, Drop, and Roll\' principle if clothing catches fire and the importance of not attempting to fight large fires."},{"order":2,"title":"Introduction to Fire Safety and Extinguishers","duration_minutes":30,"description":"A theoretical session covering the basics of fire (fire triangle), different classes of fire (A, B, C, D, K), types of fire extinguishers, and the \'PASS\' method (Pull, Aim, Squeeze, Sweep) for effective operation. Discussion on when to fight a fire versus when to evacuate."},{"order":3,"title":"Live Demonstration of Fire Extinguisher Use","duration_minutes":25,"description":"The Lead Trainer demonstrates the proper handling and operation of a fire extinguisher on a controlled, simulated fire (e.g., fire pan). Emphasis on safety distance, aiming at the base of the fire, and sweeping motion."},{"order":4,"title":"Hands-on Practice: Dry Run (PASS Method)","duration_minutes":40,"description":"Participants practice the \'PASS\' method using discharged or training fire extinguishers without live fire. This activity focuses on muscle memory for pulling the pin, aiming, squeezing the handle, and sweeping motion. Trainers provide immediate feedback."},{"order":5,"title":"Simulated Fire Extinguishment Drill","duration_minutes":40,"description":"Under strict supervision, participants take turns extinguishing a small, controlled fire (e.g., in a fire pan or designated burn area) using a live fire extinguisher. This activity tests their practical application of the \'PASS\' method in a realistic scenario."},{"order":6,"title":"Debriefing, Q&A, and Feedback","duration_minutes":20,"description":"A facilitated discussion reviewing the exercise, addressing participant questions, clarifying misconceptions, and gathering feedback. Trainers provide constructive criticism and reinforce key learning points. Certificates of participation may be distributed."}]', NULL, 'Exercise Template: How to use fire extinguisher\n\nRecommended Personnel: Lead Trainer (1), Assistant Trainer (2), Safety Officer (1), Marshal (2), Medical Team (2), Evaluator (2), Communication Officer (1)\n\nRecommended Equipment: Fire Extinguisher x2, Fire Extinguisher x5, Fire Extinguisher x8, First Aid Kit x1, Emergency Light x2\n\nActivities:\n1. Registration, Orientation & Safety Briefing (20 min)\n2. Introduction to Fire Safety and Extinguishers (30 min)\n3. Live Demonstration of Fire Extinguisher Use (25 min)\n4. Hands-on Practice: Dry Run (PASS Method) (40 min)\n5. Simulated Fire Extinguishment Drill (40 min)\n6. Debriefing, Q&A, and Feedback (20 min)\n\nEvaluation Objectives:\n• At least 90% of participants can correctly identify the four main classes of fire and their corresponding extinguisher types during post-activity questioning.\n• At least 85% of participants can execute the \'PASS\' method correctly during the dry run, demonstrating proper sequence and technique.\n• At least 80% of participants can successfully extinguish a controlled simulated fire using a fire extinguisher, applying the \'PASS\' method effectively and safely.\n• All participants adhere to safety instructions and maintain appropriate distance from the fire during the live fire drill, as observed by the Safety Officer and Evaluators.\n• At least 75% of participants express increased confidence in their ability to use a fire extinguisher in an emergency, as indicated by post-exercise feedback forms.', 1, 0, NULL, 3, 3, '2026-07-13 05:10:52', NULL, '2026-07-13 05:06:51', '2026-07-13 05:10:52', NULL, NULL, NULL, NULL, '[{"time":"08:05","label":"Registration, Orientation & Safety Briefing","description":"Participants register, receive an overview of the exercise objectives, schedule, and critical safety protocols, including emergency exits and first aid points. Emphasize the \'Stop, Drop, and Roll\' principle if clothing catches fire and the importance of not attempting to fight large fires."},{"time":"08:25","label":"Introduction to Fire Safety and Extinguishers","description":"A theoretical session covering the basics of fire (fire triangle), different classes of fire (A, B, C, D, K), types of fire extinguishers, and the \'PASS\' method (Pull, Aim, Squeeze, Sweep) for effective operation. Discussion on when to fight a fire versus when to evacuate."},{"time":"08:55","label":"Live Demonstration of Fire Extinguisher Use","description":"The Lead Trainer demonstrates the proper handling and operation of a fire extinguisher on a controlled, simulated fire (e.g., fire pan). Emphasis on safety distance, aiming at the base of the fire, and sweeping motion."},{"time":"09:20","label":"Hands-on Practice: Dry Run (PASS Method)","description":"Participants practice the \'PASS\' method using discharged or training fire extinguishers without live fire. This activity focuses on muscle memory for pulling the pin, aiming, squeezing the handle, and sweeping motion. Trainers provide immediate feedback."},{"time":"10:00","label":"Simulated Fire Extinguishment Drill","description":"Under strict supervision, participants take turns extinguishing a small, controlled fire (e.g., in a fire pan or designated burn area) using a live fire extinguisher. This activity tests their practical application of the \'PASS\' method in a realistic scenario."},{"time":"10:40","label":"Debriefing, Q&A, and Feedback","description":"A facilitated discussion reviewing the exercise, addressing participant questions, clarifying misconceptions, and gathering feedback. Trainers provide constructive criticism and reinforce key learning points. Certificates of participation may be distributed."}]', NULL),
	(4, 'Fire Extinguisher Hands-on Drill', 'Fire Safety', 'A Fire Safety simulation exercise for community disaster volunteers covering briefing, hands-on response stations, evacuation or rescue coordination, and debrief.', 'Drill', 'draft', '2026-07-07', '08:00:00', '12:00:00', 0, NULL, 'BGC', 'BGC', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, 5, 18, 4, NULL, 1, NULL, NULL, NULL, 'Barangay Officials, Community Volunteers', 23, '2026-07-10 13:40:43', 1, 1, 0, NULL, NULL, 'Wear required PPE at all times\nFollow marshal and safety officer instructions\nNo unauthorized entry to hazard zones\nReport injuries immediately', NULL, NULL, '[{"order":1,"title":"Registration and Safety Briefing","duration_minutes":15,"description":"Check-in, hazard review, and exercise rules."},{"order":2,"title":"Skills Station Rotation","duration_minutes":32,"description":"Hands-on Fire Safety response practice."},{"order":3,"title":"Scenario Activation","duration_minutes":27,"description":"Timed scenario with role-based tasks."},{"order":4,"title":"Evacuation or Recovery Phase","duration_minutes":20,"description":"Movement to assembly area and status reporting."},{"order":5,"title":"Debrief and Evaluation","duration_minutes":15,"description":"After-action review and lessons learned."}]', NULL, 'Exercise Template: Fire Extinguisher Hands-on Drill\n\nRecommended Personnel: Lead Trainer (1), Safety Officer (1), Medical Team (2), Marshal (2), Evaluator (2)\n\nRecommended Equipment: \n\nActivities:\n1. Registration and Safety Briefing (15 min)\n2. Skills Station Rotation (32 min)\n3. Scenario Activation (27 min)\n4. Evacuation or Recovery Phase (20 min)\n5. Debrief and Evaluation (15 min)\n\nEvaluation Objectives:\n• Followed safety briefing instructions\n• Executed assigned role within time limits\n• Communicated clearly with team members\n• Completed assigned tasks within the exercise timeline', 1, 0, NULL, 3, 3, NULL, NULL, '2026-07-13 05:40:53', '2026-07-13 05:40:53', NULL, NULL, NULL, NULL, '[{"time":"08:00","label":"Registration and Safety Briefing","description":"Check-in, hazard review, and exercise rules."},{"time":"08:15","label":"Skills Station Rotation","description":"Hands-on Fire Safety response practice."},{"time":"09:30","label":"Scenario Activation","description":"Timed scenario with role-based tasks."},{"time":"10:30","label":"Evacuation or Recovery Phase","description":"Movement to assembly area and status reporting."},{"time":"11:15","label":"Debrief and Evaluation","description":"After-action review and lessons learned."}]', NULL),
	(5, 'how use fire extinguisher Original', 'Fire Safety', 'A simulated small electrical fire occurs in the barangay hall\'s common area during a community meeting. Participants must identify the fire type, retrieve the correct fire extinguisher, and apply the PASS method to suppress the fire safely and effectively, while ensuring the safety of others.', 'Functional Exercise', 'draft', '2026-07-13', '13:52:00', '15:00:00', 0, NULL, 'Bestlink', 'Bestlink', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, 5, 5, 13, NULL, 1, NULL, 5, NULL, 'Barangay Officials, Community Volunteers', 25, '2026-07-11 13:40:47', 1, 0, 0, NULL, NULL, 'Always prioritize personal safety; follow all instructions from trainers and safety officers; do not attempt to extinguish large or uncontrolled fires; know the nearest exit routes; report any discomfort or injury immediately to the Medical Team.', NULL, NULL, '[{"order":1,"title":"Orientation, Registration, and Safety Briefing","duration_minutes":15,"description":"Welcome participants, provide an overview of the exercise objectives and schedule, and conduct a comprehensive safety briefing covering emergency procedures and ground rules for the simulation."},{"order":2,"title":"Lecture-Demonstration: Fire Safety Basics and PASS Method","duration_minutes":30,"description":"A theoretical session covering common causes of fires, types of fire extinguishers (Class A, B, C, D, K), and a detailed demonstration of the \'PASS\' (Pull, Aim, Squeeze, Sweep) method for operating a fire extinguisher."},{"order":3,"title":"Hands-on Practice: Fire Extinguisher Operation","duration_minutes":40,"description":"Participants will individually practice the \'PASS\' method using training fire extinguishers on a controlled, simulated fire (e.g., a fire pan with controlled fuel or a water-based fire simulator). Emphasis on proper stance and technique."},{"order":4,"title":"Scenario Simulation: Responding to a Small Fire Incident","duration_minutes":25,"description":"A controlled functional exercise where participants respond to a simulated small electrical fire in a designated area. Participants will assess the situation, decide on appropriate action, and apply the fire extinguisher as practiced."},{"order":5,"title":"Debriefing and Open Forum","duration_minutes":8,"description":"A facilitated discussion to review the exercise, gather feedback from participants, discuss lessons learned, identify strengths and areas for improvement in fire response."},{"order":6,"title":"Wrap-up and Closing Remarks","duration_minutes":2,"description":"Summary of key takeaways, acknowledgment of participants and personnel, and final announcements."}]', NULL, 'Exercise Template: how use fire extinguisher Original\n\nRecommended Personnel: Lead Trainer (1), Assistant Trainer (1), Safety Officer (1), Marshal (2), Medical Team (2), Evaluator (1), Communication Officer (1) | Assigned: Lead Trainer: Reymon\n\nRecommended Equipment: Fire Extinguisher x1, Fire Extinguisher x3, Fire Extinguisher x1, Emergency Light x1, First Aid Kit x1, Emergency Light x1\n\nActivities:\n1. Orientation, Registration, and Safety Briefing (15 min)\n2. Lecture-Demonstration: Fire Safety Basics and PASS Method (30 min)\n3. Hands-on Practice: Fire Extinguisher Operation (40 min)\n4. Scenario Simulation: Responding to a Small Fire Incident (25 min)\n5. Debriefing and Open Forum (8 min)\n6. Wrap-up and Closing Remarks (2 min)\n\nEvaluation Objectives:\n• Participants can correctly identify at least 3 common fire causes and distinguish between different fire extinguisher classes (A, B, C).\n• At least 90% of participants can demonstrate the \'PASS\' method correctly and safely during hands-on practice.\n• Participants can effectively assess a simulated small fire scenario, select the appropriate extinguisher, and apply it within 30 seconds of identifying the \'fire\'.\n• All participants and personnel adhere to established safety protocols throughout the exercise, with no safety breaches reported.\n• Exercise personnel demonstrate effective coordination and communication in managing the exercise flow and ensuring participant safety.', 1, 0, NULL, 3, 3, NULL, NULL, '2026-07-13 05:51:06', '2026-07-13 05:51:06', NULL, NULL, NULL, NULL, '[{"time":"08:15","label":"Orientation, Registration, and Safety Briefing","description":"Welcome participants, provide an overview of the exercise objectives and schedule, and conduct a comprehensive safety briefing covering emergency procedures and ground rules for the simulation."},{"time":"08:30","label":"Lecture-Demonstration: Fire Safety Basics and PASS Method","description":"A theoretical session covering common causes of fires, types of fire extinguishers (Class A, B, C, D, K), and a detailed demonstration of the \'PASS\' (Pull, Aim, Squeeze, Sweep) method for operating a fire extinguisher."},{"time":"09:00","label":"Hands-on Practice: Fire Extinguisher Operation","description":"Participants will individually practice the \'PASS\' method using training fire extinguishers on a controlled, simulated fire (e.g., a fire pan with controlled fuel or a water-based fire simulator). Emphasis on proper stance and technique."},{"time":"09:40","label":"Scenario Simulation: Responding to a Small Fire Incident","description":"A controlled functional exercise where participants respond to a simulated small electrical fire in a designated area. Participants will assess the situation, decide on appropriate action, and apply the fire extinguisher as practiced."},{"time":"10:05","label":"Debriefing and Open Forum","description":"A facilitated discussion to review the exercise, gather feedback from participants, discuss lessons learned, identify strengths and areas for improvement in fire response."},{"time":"10:13","label":"Wrap-up and Closing Remarks","description":"Summary of key takeaways, acknowledgment of participants and personnel, and final announcements."}]', NULL),
