REPLACE INTO `simulation_exercise_activities` (`id`, `template_id`, `title`, `description`, `duration_minutes`, `start_time`, `sort_order`, `created_at`, `updated_at`) VALUES
	(7, 2, 'Registration, Orientation & Safety Briefing', 'Participants register, receive an overview of the exercise objectives, schedule, and critical safety protocols, including emergency exits and first aid points. Emphasize the \'Stop, Drop, and Roll\' principle if clothing catches fire and the importance of not attempting to fight large fires.', 20, '08:05', 1, '2026-07-13 04:43:27', '2026-07-13 04:43:27'),
	(8, 2, 'Introduction to Fire Safety and Extinguishers', 'A theoretical session covering the basics of fire (fire triangle), different classes of fire (A, B, C, D, K), types of fire extinguishers, and the \'PASS\' method (Pull, Aim, Squeeze, Sweep) for effective operation. Discussion on when to fight a fire versus when to evacuate.', 30, '08:25', 2, '2026-07-13 04:43:27', '2026-07-13 04:43:27'),
	(9, 2, 'Live Demonstration of Fire Extinguisher Use', 'The Lead Trainer demonstrates the proper handling and operation of a fire extinguisher on a controlled, simulated fire (e.g., fire pan). Emphasis on safety distance, aiming at the base of the fire, and sweeping motion.', 25, '08:55', 3, '2026-07-13 04:43:27', '2026-07-13 04:43:27'),
	(10, 2, 'Hands-on Practice: Dry Run (PASS Method)', 'Participants practice the \'PASS\' method using discharged or training fire extinguishers without live fire. This activity focuses on muscle memory for pulling the pin, aiming, squeezing the handle, and sweeping motion. Trainers provide immediate feedback.', 40, '09:20', 4, '2026-07-13 04:43:27', '2026-07-13 04:43:27'),
	(11, 2, 'Simulated Fire Extinguishment Drill', 'Under strict supervision, participants take turns extinguishing a small, controlled fire (e.g., in a fire pan or designated burn area) using a live fire extinguisher. This activity tests their practical application of the \'PASS\' method in a realistic scenario.', 40, '10:00', 5, '2026-07-13 04:43:27', '2026-07-13 04:43:27'),
	(12, 2, 'Debriefing, Q&A, and Feedback', 'A facilitated discussion reviewing the exercise, addressing participant questions, clarifying misconceptions, and gathering feedback. Trainers provide constructive criticism and reinforce key learning points. Certificates of participation may be distributed.', 20, '10:40', 6, '2026-07-13 04:43:27', '2026-07-13 04:43:27'),
	(13, 3, 'Registration and Welcome Remarks', 'Participants register, receive exercise materials, and are welcomed by the exercise lead. Brief overview of the day\'s agenda and safety protocols.', 15, '08:15', 1, '2026-07-13 05:01:16', '2026-07-13 05:01:16'),
	(14, 3, 'Introduction to Fire Safety and Extinguisher Types', 'Presentation on basic fire safety principles, common causes of fire in the community, different classes of fire, and the various types of fire extinguishers and their appropriate uses.', 20, '08:30', 2, '2026-07-13 05:01:16', '2026-07-13 05:01:16'),
	(15, 3, 'Demonstration of P.A.S.S. Method', 'A Lead Trainer demonstrates the proper \'P.A.S.S.\' (Pull, Aim, Squeeze, Sweep) method for operating a fire extinguisher, emphasizing safety distance and technique. Visual aids will be used.', 20, '08:50', 3, '2026-07-13 05:01:16', '2026-07-13 05:01:16'),
	(16, 3, 'Hands-on Practice: Dry Run with Extinguishers', 'Participants will individually practice the P.A.S.S. method using training fire extinguishers (or simulated extinguishers) under the direct supervision of trainers. Focus on muscle memory and correct posture.', 45, '09:10', 4, '2026-07-13 05:01:16', '2026-07-13 05:01:16'),
	(17, 3, 'Scenario-Based Application', 'Participants are presented with a simulated small fire scenario (e.g., a controlled fire in a pan or a designated fire prop) and are tasked to apply their learned skills to \'extinguish\' it using a live (or simulated) fire extinguisher. Safety Officer will closely monitor.', 30, '09:55', 5, '2026-07-13 05:01:16', '2026-07-13 05:01:16'),
	(18, 3, 'Q&A and Review', 'Open forum for participants to ask questions, clarify doubts, and review key takeaways from the training. Trainers will reinforce critical safety points.', 15, '10:25', 6, '2026-07-13 05:01:16', '2026-07-13 05:01:16'),
	(19, 3, 'Debriefing and Closing Remarks', 'A comprehensive debriefing session to discuss observations, lessons learned, and areas for improvement. Participants provide feedback. Closing remarks and acknowledgement of participation.', 20, '10:40', 7, '2026-07-13 05:01:16', '2026-07-13 05:01:16'),
