	(119, 12, 'Debrief and Evaluation', 'After-action review and lessons learned.', 27, '11:15', 5, '2026-07-13 05:40:04', '2026-07-13 05:40:04'),
	(120, 13, 'Orientation, Registration, and Safety Briefing', 'Welcome participants, provide an overview of the exercise objectives and schedule, and conduct a comprehensive safety briefing covering emergency procedures and ground rules for the simulation.', 15, '08:15', 1, '2026-07-13 05:50:01', '2026-07-13 05:50:01'),
	(121, 13, 'Lecture-Demonstration: Fire Safety Basics and PASS Method', 'A theoretical session covering common causes of fires, types of fire extinguishers (Class A, B, C, D, K), and a detailed demonstration of the \'PASS\' (Pull, Aim, Squeeze, Sweep) method for operating a fire extinguisher.', 30, '08:30', 2, '2026-07-13 05:50:02', '2026-07-13 05:50:02'),
	(122, 13, 'Hands-on Practice: Fire Extinguisher Operation', 'Participants will individually practice the \'PASS\' method using training fire extinguishers on a controlled, simulated fire (e.g., a fire pan with controlled fuel or a water-based fire simulator). Emphasis on proper stance and technique.', 40, '09:00', 3, '2026-07-13 05:50:02', '2026-07-13 05:50:02'),
	(123, 13, 'Scenario Simulation: Responding to a Small Fire Incident', 'A controlled functional exercise where participants respond to a simulated small electrical fire in a designated area. Participants will assess the situation, decide on appropriate action, and apply the fire extinguisher as practiced.', 25, '09:40', 4, '2026-07-13 05:50:02', '2026-07-13 05:50:02'),
	(124, 13, 'Debriefing and Open Forum', 'A facilitated discussion to review the exercise, gather feedback from participants, discuss lessons learned, identify strengths and areas for improvement in fire response.', 8, '10:05', 5, '2026-07-13 05:50:02', '2026-07-13 05:50:02'),
	(125, 13, 'Wrap-up and Closing Remarks', 'Summary of key takeaways, acknowledgment of participants and personnel, and final announcements.', 2, '10:13', 6, '2026-07-13 05:50:02', '2026-07-13 05:50:02');
