REPLACE INTO `simulation_exercise_evaluation_objectives` (`id`, `template_id`, `activity_id`, `heading`, `objective_text`, `sort_order`, `created_at`, `updated_at`) VALUES
	(8, 2, NULL, 'Knowledge Retention', 'At least 90% of participants can correctly identify the four main classes of fire and their corresponding extinguisher types during post-activity questioning.', 1, '2026-07-13 04:43:27', '2026-07-13 04:43:27'),
	(9, 2, NULL, 'Skill Demonstration (Dry Run)', 'At least 85% of participants can execute the \'PASS\' method correctly during the dry run, demonstrating proper sequence and technique.', 2, '2026-07-13 04:43:27', '2026-07-13 04:43:27'),
	(10, 2, NULL, 'Practical Application (Live Fire)', 'At least 80% of participants can successfully extinguish a controlled simulated fire using a fire extinguisher, applying the \'PASS\' method effectively and safely.', 3, '2026-07-13 04:43:27', '2026-07-13 04:43:27'),
	(11, 2, NULL, 'Safety Adherence', 'All participants adhere to safety instructions and maintain appropriate distance from the fire during the live fire drill, as observed by the Safety Officer and Evaluators.', 4, '2026-07-13 04:43:27', '2026-07-13 04:43:27'),
	(12, 2, NULL, 'Confidence and Readiness', 'At least 75% of participants express increased confidence in their ability to use a fire extinguisher in an emergency, as indicated by post-exercise feedback forms.', 5, '2026-07-13 04:43:27', '2026-07-13 04:43:27'),
	(13, 3, NULL, 'Knowledge Acquisition', 'At least 80% of participants can correctly identify the four main classes of fire and their corresponding extinguisher types during a verbal quiz or written assessment.', 1, '2026-07-13 05:01:16', '2026-07-13 05:01:16'),
	(14, 3, NULL, 'Skill Demonstration', '90% of participants will correctly execute all four steps of the P.A.S.S. method (Pull, Aim, Squeeze, Sweep) during the dry run practice, as observed by trainers.', 2, '2026-07-13 05:01:16', '2026-07-13 05:01:16'),
	(15, 3, NULL, 'Scenario Application', '75% of participants, when presented with a simulated fire scenario, will successfully \'extinguish\' the fire using the correct extinguisher and technique within a reasonable timeframe (e.g., 30 seconds).', 3, '2026-07-13 05:01:16', '2026-07-13 05:01:16'),
	(16, 3, NULL, 'Safety Compliance', 'All participants will adhere to safety protocols and instructions from the Safety Officer throughout the entire exercise, with no reported safety breaches.', 4, '2026-07-13 05:01:16', '2026-07-13 05:01:16'),
	(17, 3, NULL, 'Confidence and Readiness', '85% of participants will express increased confidence in their ability to use a fire extinguisher effectively, as indicated by post-exercise feedback forms.', 5, '2026-07-13 05:01:16', '2026-07-13 05:01:16'),
