	(98, 13, NULL, 'Knowledge of Fire Safety', 'Participants can correctly identify at least 3 common fire causes and distinguish between different fire extinguisher classes (A, B, C).', 1, '2026-07-13 05:50:02', '2026-07-13 05:50:02'),
	(99, 13, NULL, 'Proficiency in PASS Method', 'At least 90% of participants can demonstrate the \'PASS\' method correctly and safely during hands-on practice.', 2, '2026-07-13 05:50:02', '2026-07-13 05:50:02'),
	(100, 13, NULL, 'Scenario Response Effectiveness', 'Participants can effectively assess a simulated small fire scenario, select the appropriate extinguisher, and apply it within 30 seconds of identifying the \'fire\'.', 3, '2026-07-13 05:50:02', '2026-07-13 05:50:02'),
	(101, 13, NULL, 'Adherence to Safety Protocols', 'All participants and personnel adhere to established safety protocols throughout the exercise, with no safety breaches reported.', 4, '2026-07-13 05:50:02', '2026-07-13 05:50:02'),
	(102, 13, NULL, 'Team Coordination (Personnel)', 'Exercise personnel demonstrate effective coordination and communication in managing the exercise flow and ensuring participant safety.', 5, '2026-07-13 05:50:02', '2026-07-13 05:50:02');
