	(6, 2, 'Lead Trainer', NULL, 1, 'Responsible for overall conduct, theoretical sessions, and live demonstrations.', 1, '2026-07-13 04:43:27', '2026-07-13 04:43:27'),
	(7, 2, 'Assistant Trainer', NULL, 2, 'Assists Lead Trainer, supervises hands-on practice, and provides individual coaching.', 2, '2026-07-13 04:43:27', '2026-07-13 04:43:27'),
	(8, 2, 'Safety Officer', NULL, 1, 'Ensures strict adherence to safety protocols, especially during live fire activities. Monitors participant well-being.', 3, '2026-07-13 04:43:27', '2026-07-13 04:43:27'),
	(9, 2, 'Marshal', NULL, 2, 'Manages participant flow, crowd control, and guides individuals to designated areas.', 4, '2026-07-13 04:43:27', '2026-07-13 04:43:27'),
	(10, 2, 'Medical Team', NULL, 2, 'On standby with first aid equipment for any medical emergencies or minor injuries.', 5, '2026-07-13 04:43:27', '2026-07-13 04:43:27'),
	(11, 2, 'Evaluator', NULL, 2, 'Observes and assesses participant performance, adherence to procedures, and overall exercise effectiveness.', 6, '2026-07-13 04:43:27', '2026-07-13 04:43:27'),
	(12, 2, 'Communication Officer', NULL, 1, 'Manages internal communications, coordinates with external agencies if needed, and documents the exercise.', 7, '2026-07-13 04:43:27', '2026-07-13 04:43:27'),
	(13, 3, 'Lead Trainer', NULL, 1, 'Responsible for overall exercise conduct, main lectures, and demonstrations.', 1, '2026-07-13 05:01:16', '2026-07-13 05:01:16'),
	(14, 3, 'Assistant Trainer', NULL, 2, 'Assists the Lead Trainer, provides one-on-one guidance during hands-on practice, and ensures participant engagement.', 2, '2026-07-13 05:01:16', '2026-07-13 05:01:16'),
	(15, 3, 'Safety Officer', NULL, 1, 'Ensures adherence to all safety protocols, manages potential hazards, and is prepared for any medical emergencies. Oversees the live fire scenario.', 3, '2026-07-13 05:01:16', '2026-07-13 05:01:16'),
	(16, 3, 'Marshal', NULL, 2, 'Assists with participant registration, crowd control, guiding participants, and maintaining order during the drill.', 4, '2026-07-13 05:01:16', '2026-07-13 05:01:16'),
	(17, 3, 'Medical Team', NULL, 2, 'On standby with a First Aid Kit to address any minor injuries or health concerns during the exercise.', 5, '2026-07-13 05:01:16', '2026-07-13 05:01:16'),
	(18, 3, 'Evaluator', NULL, 1, 'Observes participant performance, collects data on exercise objectives, and contributes to the debriefing.', 6, '2026-07-13 05:01:16', '2026-07-13 05:01:16'),
	(19, 3, 'Communication Officer', NULL, 1, 'Manages internal communications, documentation (photos/videos), and ensures smooth information flow.', 7, '2026-07-13 05:01:16', '2026-07-13 05:01:16'),
