REPLACE INTO `simulation_exercise_templates` (`id`, `title`, `category`, `exercise_type`, `evaluation_mode`, `difficulty_level`, `estimated_duration_minutes`, `objectives`, `scenario_summary`, `expected_hazards`, `learning_objectives`, `safety_reminders`, `status`, `created_by_id`, `updated_by_id`, `created_at`, `updated_at`) VALUES
	(1, 'Fire Safety Practical Training', 'Fire Safety', 'Drill', 'team', 'Intermediate', 125, 'Equip barangay responders and volunteers with practical Fire Safety skills through structured drills, coordination, and after-action review.', 'A Fire Safety simulation exercise for community disaster volunteers covering briefing, hands-on response stations, evacuation or rescue coordination, and debrief.', 'Secondary hazards during Fire Safety response\nCrowd panic\nCommunication delays\nIncomplete PPE usage', 'Apply Fire Safety response procedures\nCoordinate with assigned roles\nExecute evacuation or rescue protocols\nParticipate in structured debrief', 'Wear required PPE at all times\nFollow marshal and safety officer instructions\nNo unauthorized entry to hazard zones\nReport injuries immediately', 'published', NULL, 1, '2026-07-13 00:29:28', '2026-07-13 05:38:44'),
	(2, 'How to use fire extinguisher', 'Fire Safety', 'Drill', 'individual', 'Intermediate', 175, 'To equip participants with the fundamental knowledge and practical skills required to safely and effectively use a fire extinguisher in an emergency, adhering to the PASS method.', 'Participants are community members attending a fire safety drill. The drill simulates a small, contained fire incident (e.g., a trash bin fire or a small liquid spill fire) in a designated open area. The objective is for participants to correctly identify the fire type, select the appropriate extinguisher, and apply the \'PASS\' method to safely put out the fire.', 'Minor burns, smoke inhalation (minimal due to controlled environment), slips/falls, equipment malfunction, panic or improper handling of equipment.', 'Participants will be able to: 1) Identify different classes of fire. 2) Select the correct type of fire extinguisher for a given fire class. 3) Demonstrate the \'PASS\' method correctly and confidently. 4) Understand when to evacuate versus when to attempt fire suppression. 5) Maintain personal safety during fire extinguisher operation.', 'Always prioritize personal safety. Do not attempt to fight fires that are too large, spreading rapidly, or if you lack a clear escape route. Ensure proper PPE (gloves, safety glasses) if provided. Follow all instructions from the Safety Officer and Trainers. Report any discomfort or incident immediately.', 'published', 3, 3, '2026-07-13 04:43:27', '2026-07-20 03:10:09'),
	(3, 'How to use fire extinguisher', 'Fire Safety', 'Drill', 'individual', 'Intermediate', 165, 'To equip LGU personnel and community members with the fundamental knowledge and practical skills required for the safe and effective use of a fire extinguisher during an emergency, thereby enhancing immediate response capabilities to small-scale fire incidents.', 'A small, contained fire has erupted in a designated area (e.g., a trash bin, a cooking pan, or a simulated electrical panel) within a community center or LGU office. Participants, acting as immediate responders, must identify the fire type, select the appropriate extinguisher, and apply the P.A.S.S. method to \'extinguish\' the fire safely and effectively.', 'Minor burns (simulated or real if using live fire), smoke inhalation (if using actual smoke), slips/falls, improper handling of equipment, panic (simulated).', 'Participants will be able to: 1) Identify different fire classes. 2) Select the correct fire extinguisher for a given fire type. 3) Demonstrate the P.A.S.S. method correctly. 4) Maintain personal safety while operating a fire extinguisher. 5) Respond calmly and effectively to a small fire incident.', 'Always prioritize personal safety. Maintain a safe distance from the fire. Never turn your back on a fire. Report any unsafe conditions immediately. Follow all instructions from the Safety Officer and Trainers. First Aid Kit and Medical Team are on standby.', 'published', 3, 3, '2026-07-13 05:01:16', '2026-07-20 03:10:09'),
	(4, 'Fire Extinguisher Hands-on Drill', 'Fire Safety', 'Drill', 'individual', 'Intermediate', 90, 'Equip barangay responders and volunteers with practical Fire Safety skills through structured drills, coordination, and after-action review.', 'A Fire Safety simulation exercise for community disaster volunteers covering briefing, hands-on response stations, evacuation or rescue coordination, and debrief.', 'Secondary hazards during Fire Safety response\nCrowd panic\nCommunication delays\nIncomplete PPE usage', 'Apply Fire Safety response procedures\nCoordinate with assigned roles\nExecute evacuation or rescue protocols\nParticipate in structured debrief', 'Wear required PPE at all times\nFollow marshal and safety officer instructions\nNo unauthorized entry to hazard zones\nReport injuries immediately', 'published', 1, 1, '2026-07-13 05:38:44', '2026-07-20 03:10:09'),
	(5, 'Earthquake Drop-Cover-Hold Drill', 'Earthquake', 'Drill', 'team', 'Intermediate', 75, 'Equip barangay responders and volunteers with practical Earthquake skills through structured drills, coordination, and after-action review.', 'A Earthquake simulation exercise for community disaster volunteers covering briefing, hands-on response stations, evacuation or rescue coordination, and debrief.', 'Secondary hazards during Earthquake response\nCrowd panic\nCommunication delays\nIncomplete PPE usage', 'Apply Earthquake response procedures\nCoordinate with assigned roles\nExecute evacuation or rescue protocols\nParticipate in structured debrief', 'Wear required PPE at all times\nFollow marshal and safety officer instructions\nNo unauthorized entry to hazard zones\nReport injuries immediately', 'published', 1, 1, '2026-07-13 05:38:44', '2026-07-13 05:38:44'),
	(6, 'Earthquake Evacuation Functional Exercise', 'Earthquake', 'Functional Exercise', 'team', 'Intermediate', 120, 'Equip barangay responders and volunteers with practical Earthquake skills through structured drills, coordination, and after-action review.', 'A Earthquake simulation exercise for community disaster volunteers covering briefing, hands-on response stations, evacuation or rescue coordination, and debrief.', 'Secondary hazards during Earthquake response\nCrowd panic\nCommunication delays\nIncomplete PPE usage', 'Apply Earthquake response procedures\nCoordinate with assigned roles\nExecute evacuation or rescue protocols\nParticipate in structured debrief', 'Wear required PPE at all times\nFollow marshal and safety officer instructions\nNo unauthorized entry to hazard zones\nReport injuries immediately', 'published', 1, 1, '2026-07-13 05:38:44', '2026-07-13 05:38:44'),
	(7, 'Flood Early Warning Drill', 'Flood', 'Drill', 'team', 'Intermediate', 100, 'Equip barangay responders and volunteers with practical Flood skills through structured drills, coordination, and after-action review.', 'A Flood simulation exercise for community disaster volunteers covering briefing, hands-on response stations, evacuation or rescue coordination, and debrief.', 'Secondary hazards during Flood response\nCrowd panic\nCommunication delays\nIncomplete PPE usage', 'Apply Flood response procedures\nCoordinate with assigned roles\nExecute evacuation or rescue protocols\nParticipate in structured debrief', 'Wear required PPE at all times\nFollow marshal and safety officer instructions\nNo unauthorized entry to hazard zones\nReport injuries immediately', 'published', 1, 1, '2026-07-13 05:38:44', '2026-07-13 05:38:44'),
	(8, 'Flood Rescue Boat Deployment Exercise', 'Flood', 'Functional Exercise', 'team', 'Intermediate', 150, 'Equip barangay responders and volunteers with practical Flood skills through structured drills, coordination, and after-action review.', 'A Flood simulation exercise for community disaster volunteers covering briefing, hands-on response stations, evacuation or rescue coordination, and debrief.', 'Secondary hazards during Flood response\nCrowd panic\nCommunication delays\nIncomplete PPE usage', 'Apply Flood response procedures\nCoordinate with assigned roles\nExecute evacuation or rescue protocols\nParticipate in structured debrief', 'Wear required PPE at all times\nFollow marshal and safety officer instructions\nNo unauthorized entry to hazard zones\nReport injuries immediately', 'published', 1, 1, '2026-07-13 05:38:44', '2026-07-13 05:38:44'),
	(9, 'Typhoon Pre-Landfall Evacuation Drill', 'Typhoon', 'Drill', 'team', 'Intermediate', 110, 'Equip barangay responders and volunteers with practical Typhoon skills through structured drills, coordination, and after-action review.', 'A Typhoon simulation exercise for community disaster volunteers covering briefing, hands-on response stations, evacuation or rescue coordination, and debrief.', 'Secondary hazards during Typhoon response\nCrowd panic\nCommunication delays\nIncomplete PPE usage', 'Apply Typhoon response procedures\nCoordinate with assigned roles\nExecute evacuation or rescue protocols\nParticipate in structured debrief', 'Wear required PPE at all times\nFollow marshal and safety officer instructions\nNo unauthorized entry to hazard zones\nReport injuries immediately', 'published', 1, 1, '2026-07-13 05:38:44', '2026-07-13 05:38:44'),
	(10, 'Landslide Community Evacuation Drill', 'Landslide', 'Drill', 'team', 'Intermediate', 95, 'Equip barangay responders and volunteers with practical Landslide skills through structured drills, coordination, and after-action review.', 'A Landslide simulation exercise for community disaster volunteers covering briefing, hands-on response stations, evacuation or rescue coordination, and debrief.', 'Secondary hazards during Landslide response\nCrowd panic\nCommunication delays\nIncomplete PPE usage', 'Apply Landslide response procedures\nCoordinate with assigned roles\nExecute evacuation or rescue protocols\nParticipate in structured debrief', 'Wear required PPE at all times\nFollow marshal and safety officer instructions\nNo unauthorized entry to hazard zones\nReport injuries immediately', 'published', 1, 1, '2026-07-13 05:38:44', '2026-07-13 05:38:44'),
	(11, 'Barangay First Aid Response Drill', 'First Aid', 'Drill', 'team', 'Intermediate', 85, 'Equip barangay responders and volunteers with practical First Aid skills through structured drills, coordination, and after-action review.', 'A First Aid simulation exercise for community disaster volunteers covering briefing, hands-on response stations, evacuation or rescue coordination, and debrief.', 'Secondary hazards during First Aid response\nCrowd panic\nCommunication delays\nIncomplete PPE usage', 'Apply First Aid response procedures\nCoordinate with assigned roles\nExecute evacuation or rescue protocols\nParticipate in structured debrief', 'Wear required PPE at all times\nFollow marshal and safety officer instructions\nNo unauthorized entry to hazard zones\nReport injuries immediately', 'published', 1, 1, '2026-07-13 05:38:44', '2026-07-13 05:38:44'),
	(12, 'Multi-Hazard Barangay Coordination Exercise', 'Multi-Hazard', 'Full Scale Exercise', 'team', 'Intermediate', 180, 'Equip barangay responders and volunteers with practical Multi-Hazard skills through structured drills, coordination, and after-action review.', 'A Multi-Hazard simulation exercise for community disaster volunteers covering briefing, hands-on response stations, evacuation or rescue coordination, and debrief.', 'Secondary hazards during Multi-Hazard response\nCrowd panic\nCommunication delays\nIncomplete PPE usage', 'Apply Multi-Hazard response procedures\nCoordinate with assigned roles\nExecute evacuation or rescue protocols\nParticipate in structured debrief', 'Wear required PPE at all times\nFollow marshal and safety officer instructions\nNo unauthorized entry to hazard zones\nReport injuries immediately', 'published', 1, 1, '2026-07-13 05:38:44', '2026-07-13 05:38:44'),
	(13, 'how use fire extinguisher Original', 'Fire Safety', 'Functional Exercise', 'individual', 'Intermediate', 120, 'To enhance the knowledge and practical skills of community members and LGU personnel in basic fire safety, proper handling, and effective use of fire extinguishers during small fire incidents within the community.', 'A simulated small electrical fire occurs in the barangay hall\'s common area during a community meeting. Participants must identify the fire type, retrieve the correct fire extinguisher, and apply the PASS method to suppress the fire safely and effectively, while ensuring the safety of others.', 'Simulated smoke (non-toxic), potential for minor burns (controlled simulation), panic among participants (simulated), and potential for equipment malfunction.', 'To effectively operate a fire extinguisher using the PASS method; to correctly identify appropriate fire extinguisher types for different fire classes; to respond calmly and decisively to a small fire incident; to understand basic immediate actions for personal and community safety during a fire.', 'Always prioritize personal safety; follow all instructions from trainers and safety officers; do not attempt to extinguish large or uncontrolled fires; know the nearest exit routes; report any discomfort or injury immediately to the Medical Team.', 'published', 3, 3, '2026-07-13 05:50:01', '2026-07-20 03:10:09');
REPLACE INTO `simulation_exercise_timeline_items` (`id`, `template_id`, `start_time`, `label`, `description`, `activity_id`, `sort_order`, `created_at`, `updated_at`) VALUES
	(13, 3, '08:15', 'Registration and Welcome Remarks', 'Participants register, receive exercise materials, and are welcomed by the exercise lead. Brief overview of the day\'s agenda and safety protocols.', 13, 1, '2026-07-13 05:01:16', '2026-07-13 05:01:16'),
	(14, 3, '08:30', 'Introduction to Fire Safety and Extinguisher Types', 'Presentation on basic fire safety principles, common causes of fire in the community, different classes of fire, and the various types of fire extinguishers and their appropriate uses.', 14, 2, '2026-07-13 05:01:16', '2026-07-13 05:01:16'),
	(15, 3, '08:50', 'Demonstration of P.A.S.S. Method', 'A Lead Trainer demonstrates the proper \'P.A.S.S.\' (Pull, Aim, Squeeze, Sweep) method for operating a fire extinguisher, emphasizing safety distance and technique. Visual aids will be used.', 15, 3, '2026-07-13 05:01:16', '2026-07-13 05:01:16'),
	(16, 3, '09:10', 'Hands-on Practice: Dry Run with Extinguishers', 'Participants will individually practice the P.A.S.S. method using training fire extinguishers (or simulated extinguishers) under the direct supervision of trainers. Focus on muscle memory and correct posture.', 16, 4, '2026-07-13 05:01:16', '2026-07-13 05:01:16'),
	(17, 3, '09:55', 'Scenario-Based Application', 'Participants are presented with a simulated small fire scenario (e.g., a controlled fire in a pan or a designated fire prop) and are tasked to apply their learned skills to \'extinguish\' it using a live (or simulated) fire extinguisher. Safety Officer will closely monitor.', 17, 5, '2026-07-13 05:01:16', '2026-07-13 05:01:16'),
	(18, 3, '10:25', 'Q&A and Review', 'Open forum for participants to ask questions, clarify doubts, and review key takeaways from the training. Trainers will reinforce critical safety points.', 18, 6, '2026-07-13 05:01:16', '2026-07-13 05:01:16'),
	(19, 3, '10:40', 'Debriefing and Closing Remarks', 'A comprehensive debriefing session to discuss observations, lessons learned, and areas for improvement. Participants provide feedback. Closing remarks and acknowledgement of participation.', 19, 7, '2026-07-13 05:01:16', '2026-07-13 05:01:16'),
