	(1, 1, 'Drill', NULL, NULL, NULL, NULL, NULL, 'LGU Fire Drill: Building Evacuation and Initial Response Procedures', 'Fire', '++ Guide building occupants through designated evacuation routes to safe assembly points efficiently\n++ Execute initial fire suppression procedures using appropriate equipment for simulated fire incidents\n++ Establish and maintain clear communication channels for reporting incident status and resource requirements', NULL, NULL, NULL, NULL, NULL, NULL, 'Reymon', NULL, 'Reymon', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'saved', 3, 3, '2026-07-09 14:38:05', '2026-07-09 14:38:05');
